#                                     borders. Added New-
#                                     EmailLogoLinkedResource and the
#                                     $EmailLogoEnabled /
#                                     $EmailLogoContentId /
#                                     $EmailLogoWidth / $EmailLogoHeight
#                                     / $EmailLogoBase64 toggles in
#                                     VARIABLES; the feature is non-
#                                     fatal and the toggle suppresses
#                                     both the image cell and the linked
#                                     resource together. No change to
#                                     the scan logic, matching rule, or
#                                     report contents.
#   3.20 2026-06-16  Alan W Phillips  Added the Certerator banner image
#                                     to the attached Expiring
#                                     Certificate Scan report (Build-
#                                     CertScanHtmlReport), below the
#                                     title and meta line and above the
#                                     column headers. Unlike the menu
#                                     option 6 summary email logo
#                                     (3.19), this report is delivered
#                                     as a standalone HTML attachment
#                                     opened directly in a browser, so
#                                     the banner is embedded as a Base64
#                                     JPEG data URI (860x573) rather
#                                     than a cid: linked resource, which
#                                     only applies inside a mail
#                                     envelope. Added the
#                                     $ScanReportBannerEnabled /
#                                     $ScanReportBannerMaxWidth /
#                                     $ScanReportBannerBase64 toggles in
#                                     VARIABLES; the banner is emitted
#                                     with an inline style (responsive
#                                     width capped at the configured
#                                     max) and $ScanReportBannerEnabled
#                                     set to $false suppresses it. No
#                                     change to the scan logic, matching
#                                     rule, report rows, or the scanned-
#                                     server report.
#   3.21 2026-06-16  Alan W Phillips  Added menu option 7, the "45 Day
#                                     Certificate Expiration Report",
#                                     porting the AD discovery, parallel
#                                     WinRM scan, template friendly-name
#                                     resolution, and HTML body
#                                     construction from
#                                     CertificateExpiryReport.ps1 into the
#                                     canonical helper-function and
#                                     logging model.
#                                     Get-ExpiryReportServerList
#                                     enumerates server computer objects
#                                     by name pattern (with the Machines
#                                     sub-OU and zMaintenance OU
#                                     exclusions),
#                                     Get-ExpiryReportTemplateMap maps
#                                     template OIDs and common names to AD
#                                     display names, and
#                                     Invoke-ExpiryReportScan reads each
#                                     reachable server's LocalMachine\My
#                                     store across a throttled
#                                     RunspacePool, classifying
#                                     Server/Client EKU usage and flagging
#                                     Expired vs ExpiringSoon.
#                                     Build-ExpiryReportBody renders the
#                                     same "UH Server Certificates
#                                     Expiring Within 45 Days" table,
#                                     execution summary, and
#                                     unreachable-category breakdown as
#                                     the source report. Per the request
#                                     the email carries the body only (no
#                                     Excel or HTML attachments), and the
#                                     existing inline Certerator logo (the
#                                     cid: linked resource) is placed
#                                     above the heading; the message is
#                                     sent through the existing
#                                     Send-ReportEmail -IncludeLogo path
#                                     with the canonical ScriptName -
#                                     MM-dd-yyyy subject. Added the
#                                     EXPIRATION REPORT region helpers and
#                                     the $ExpiryReport* configuration
#                                     block in VARIABLES. The menu Exit
#                                     action moved to option 8. No change
#                                     to options 1-6 or any existing
#                                     pipeline, scan, report, or email
#                                     logic.
#   3.22 2026-06-16  Alan W Phillips  Changed the menu option 7 email
#                                     subject to "Certerator <N> Day
#                                     Expiring Certificate Report -
#                                     MM-dd-yyyy" via the new
#                                     Get-ExpiryReportEmailSubject helper,
#                                     passed to Send-ReportEmail with
#                                     -Subject (replacing the default
#                                     ScriptName - MM-dd-yyyy subject used
#                                     in 3.21). The day count is drawn
#                                     from $ExpiryReportDaysThreshold so
#                                     the subject tracks the configured
#                                     window. No other change to option 7
#                                     or any existing logic.
#   3.23 2026-06-16  Alan W Phillips  Set the menu option 7 email subject
#                                     to the fixed literal "Certerator 45
#                                     Day Expiring Certificate Report -
#                                     MM-dd-yyyy" in
#                                     Get-ExpiryReportEmailSubject,
#                                     removing the prior dependency on
#                                     $ExpiryReportDaysThreshold for the
#                                     subject text. No other change.
#   3.24 2026-06-16  Alan W Phillips  Updated the main menu header title
#                                     from "Jeffs_Certerator" to "JEFF'S
#                                     CERTERATOR" rendered in Yellow,
#                                     while the surrounding "=" bars
#                                     remain Cyan. Header width unchanged
#                                     at 58 characters. Cosmetic only; no
#                                     logic change.

#   3.25 2026-06-16  Alan W Phillips  Made $ExpiryReportDaysThreshold the
#                                     single authoritative source for the
#                                     report window. The menu option 7
#                                     label, the option 7 console section
#                                     header, and the email subject now
#                                     all derive their day count from
#                                     $ExpiryReportDaysThreshold instead
#                                     of a hardcoded "45", keeping the
#                                     menu and email in sync if the
#                                     threshold changes. The email body
#                                     heading and execution summary
#                                     already referenced the variable.
#                                     Menu column alignment preserved.

#   3.26 2026-06-16  Alan W Phillips  Renamed the menu option 7
#                                     orchestrator function from
#                                     Invoke-FortyFiveDayExpiryReport to
#                                     Invoke-ExpiryReport (definition and
#                                     call site) and reworded the header
#                                     Description to refer to "the
#                                     configured window" instead of a
#                                     hardcoded "45 days". No behavioral
#                                     change.

#
# =====================================================================

# ============================================================
# REGION: VARIABLES
# ============================================================

# --- Identity / dates ---
$ScriptName   = 'Jeffs_Certerator'
$ReportTitle  = "Jeff's Certerator Certificate Report"   # Heading shown in the HTML email body.
$FriendlyDate = Get-Date -Format 'dddd, MMMM dd, yyyy'
$RunStamp     = Get-Date -Format 'yyyy-MM-dd_HH-mm-ss'

# --- Behavior toggles ---
$DryRun           = $false   # $true = log intended actions only; no writes, no submission, no remote ops.
$SendEmail        = $true    # $true = email the HTML report on completion.
$UseParallel      = $true    # $true = process servers via RunspacePool; $false = sequential.
$ExportPfx        = $true    # $true = build full-chain PFX from key + issued cert.
$DeployToRemote   = $true    # $true = copy artifacts to each target's remote cert directory.
$BindIis          = $true    # $true = import PFX and bind to IIS HTTPS on each target.
$VerifyDeployment = $true    # $true = re-check deployed files and IIS binding after deploy.

# --- Parallelism ---
$MaxConcurrency = 5          # Maximum concurrent server runspaces.

# --- SMTP / email (open relay, no authentication) ---
$SmtpServer = 'smtp.uhhs.com'
$SmtpPort   = 25
$MailFrom   = 'Certerator@uhhs.com'
$MailTo     = @(
    'Alan.Phillips@UHhospitals.org'
    'Jeffrey.Altomari@UHhospitals.org'
)

# --- Email summary logo (inline CID image, menu option 6 summary) ---
# Rendered to the right of the metrics table in the scan summary email.
# Embedded as Base64 and delivered as a System.Net.Mail LinkedResource
# referenced by a cid: URI; data: URIs are not honored by Outlook desktop.
# Setting $EmailLogoEnabled to $false suppresses both the inline image and
# the linked resource.
$EmailLogoEnabled   = $true
$EmailLogoContentId = 'certeratorlogo'
$EmailLogoWidth     = 360
$EmailLogoHeight    = 240
$EmailLogoMimeType  = 'image/png'   
$EmailLogoBase64    = ''

# --- Email body approved logo (inline CID image, menu option 7 above report) ---
# Embedded as Base64 and delivered as a System.Net.Mail LinkedResource
# referenced by a cid: URI; data: URIs are not honored by Outlook desktop.
# Setting $EmailBodyLogoEnabled to $false suppresses both the inline image and
# the linked resource.
$EmailBodyLogoEnabled   = $true
$EmailBodyLogoContentId = 'certeratorbodylogo'
$EmailBodyLogoWidth     = 240
$EmailBodyLogoHeight    = 240
$EmailBodyLogoMimeType  = 'image/jpeg'
$EmailBodyLogoBase64    = ''

# --- Expiring-cert scan report banner (embedded in the attached HTML) ---
# Shown below the title/meta line and above the column headers in the
# attached Expiring Certificate Scan report. Embedded as a Base64 data URI
# because that report is opened as a standalone file in a browser (no mail
# envelope, so cid: references do not apply). $false suppresses the banner.
# NOTE: source file is PNG data (860 x 573) despite the .jpg name - the data
#       URI prefix must be 'data:image/png;base64,' not image/jpeg.
$ScanReportBannerEnabled  = $true
$ScanReportBannerMaxWidth = 860
$ScanReportBannerMimeType = 'image/png'
$ScanReportBannerBase64   = ''

# --- Filesystem / logging paths ---
$OutputRoot = 'C:\Temp\Certerator'
$LogRoot    = Join-Path -Path $OutputRoot -ChildPath 'Logs'
$LogFile    = Join-Path -Path $LogRoot -ChildPath ('{0}_{1}.log' -f $ScriptName, $RunStamp)

# --- OpenSSL / PKI tooling ---
$OpenSSLPath = 'C:\Program Files\OpenSSL-Win64\bin\openssl.exe'
$KeyLength   = 2048

# --- Issuing CA ---
# Format: "CAHostName\CA Common Name". If left blank, the script prompts
# for it at runtime.
$CAConfig = 'uhpkisub03\University Hospitals Sub CA 3'

# --- Remote deployment / IIS ---
$RemoteCertDir = 'E:\cert'              # Target directory on each remote server.
$IISSiteName   = 'Default Web Site'     # IIS site to bind the certificate to.
$IISBindPort   = 443                    # HTTPS binding port.

# --- PFX / chain ---
# $PFXPassword is left blank; if blank and $ExportPfx is $true the script
# prompts for it once as a SecureString. $CAChainFile, if set to a PEM file
# holding the issuing + root certificates, overrides the .NET chain build.
$PFXPassword = ''
$CAChainFile = ''

# --- DNS domains used to build default SAN entries ---
$PrimaryDomain   = 'uhhs.com'           # CN / primary FQDN domain
$AlternateDomain = 'uhhospitals.org'    # additional default SAN domain

# --- Subject Distinguished Name fields ---
$Country      = 'US'
$State        = 'Ohio'
$Locality     = 'Cleveland'
$Organization = 'University Hospitals'
$OrgUnit      = 'Information Technology'

# --- Certificate templates offered in the menu ---
# FriendlyName is shown in the menu; CommonName is what certreq submits via
# "CertificateTemplate:<name>". These differ when a template's display name
# contains spaces (the CA expects the space-free internal CN). Confirm any
# additional templates with: certutil -template
$CertTemplates = [ordered]@{
    '1' = [PSCustomObject]@{
        FriendlyName = '__UH__Web Server__SAN__2048__V2'
        CommonName   = '__UH__WebServer__SAN__2048__V2'
    }
    '2' = [PSCustomObject]@{
        FriendlyName = '__UH__Domain Controller Authentication__SAN__2048__V2'
        CommonName   = '__UH__DomainControllerAuthentication__SAN__2048__V2'
    }
    '3' = [PSCustomObject]@{
        FriendlyName = '__UH__RDS__Authentication'
        CommonName   = '__UH__RDS__Authentication'
    }
    '4' = [PSCustomObject]@{
        FriendlyName = '__UH__EPIC__SAN__2048__V2'
        CommonName   = '__UH__EPIC__SAN__2048__V2'
    }
}

# --- Console color map for log levels ---
$LevelColors = @{
    'INFO '  = 'Cyan'
    'OK   '  = 'Green'
    'WARN '  = 'Yellow'
    'ERROR'  = 'Red'
    'DRYRUN' = 'Magenta'
}

# --- Runtime-populated holders (set during a run) ---
$SACred  = $null    # PSCredential for remote operations.
$PfxPlain = $null   # Plaintext PFX password marshalled into worker config.
$UseCurrentIdentity = $false   # $true = run remote stages as the current -sa logon (no prompt).

# --- PFX inspection / re-issue ---
$InspectRoot = Join-Path -Path $OutputRoot -ChildPath 'Inspect'   # CER/CRT export target.

# --- Certificate extension OIDs (used to read template + SAN data) ---
$OidTemplateInfo   = '1.3.6.1.4.1.311.21.7'   # Certificate Template Information (V2+).
$OidTemplateNameV1 = '1.3.6.1.4.1.311.20.2'   # Certificate Template Name (V1).
$OidSubjectAltName = '2.5.29.17'              # Subject Alternative Name.

# --- Root CRL maintenance (menu option 5) ---
# Hidden password gating the CRL update action; the workflow always performs
# an explanatory DryRun first and only executes after operator confirmation.
$CrlMenuPassword     = '1001001SOS'                       # Masked-entry password for the CRL action.
$CrlMenuMaxAttempts  = 3                                  # Password attempts before returning to the menu.
$vCenterServer       = 'UHVSPHCON01.uhhs.com'             # vCenter managing the CA virtual machines.
$RootCAServer        = 'UHPKIROOT02'                      # Offline Root CA VM name (vCenter inventory).
$SubCAServer         = 'UHPKISUB03'                       # Issuing Sub CA VM name (vCenter inventory).
$RootUsername        = 'Administrator'                    # Local Root CA account for Invoke-VMScript.
$RootPassword        = 'bCoF5N53'                         # Local Root CA password (guest credential).
$ToolsTimeoutSeconds = 600                                # Max seconds to wait for VMware Tools.
$RootCaIssuerName    = 'University Hospitals Root CA 2'    # Expected CRL issuer used for validation.

# --- Root CRL maintenance: OS-derived paths (resolved on this host) ---
$CrlSystemRoot     = $env:SystemRoot
$CrlSystemDrive    = $env:SystemDrive.TrimEnd('\')
$CrlSystemRootName = Split-Path -Path $CrlSystemRoot -Leaf
$CrlSystem32Path   = Join-Path -Path $CrlSystemRoot -ChildPath 'System32'

# --- Root CRL maintenance: PKI paths ---
$CertEnrollPath       = Join-Path -Path $CrlSystem32Path -ChildPath 'CertSrv\CertEnroll'
$CRLNamePattern       = 'University Hospitals Root CA 2*.crl'
$CRLSharePath         = '\\{0}\{1}$\pki\crl' -f $SubCAServer, $CrlSystemDrive.TrimEnd(':')
$CRLSubCertEnrollPath = '\\{0}\{1}$\{2}\System32\CertSrv\CertEnroll' -f $SubCAServer, $CrlSystemDrive.TrimEnd(':'), $CrlSystemRootName
$SubCACRLPath         = 'E:\pki\crl\University Hospitals Root CA 2.crl'

# --- Domain certificate-expiry scan (menu option 6) ---
# Enumerates server computer objects in the domain and reports every
# certificate in $CertScanStorePath whose NotAfter date matches the target
# date. $CertScanTargetDate is offered as the default at runtime and can be
# overridden interactively; the resolved value is held in
# $CertScanResolvedDate for the worker configuration.
$CertScanTargetDate   = '2026-10-31'                                      # Expiry date to match (yyyy-MM-dd).
$CertScanResolvedDate = $CertScanTargetDate                               # Runtime-resolved target date (set by the menu action).
$CertScanADServer     = 'uhhs.com'                                        # AD domain / DC queried for computer objects.
$CertScanServerFilter = 'Enabled -eq $true -and OperatingSystem -like "*Server*"'   # Get-ADComputer -Filter string.
$CertScanSearchBase   = ''                                                # Optional OU distinguished name; blank = whole domain.
$CertScanStorePath    = 'Cert:\LocalMachine\My'                          # Certificate store inspected on each server.
$CertScanMaxServers   = 0                                                 # 0 = no cap; >0 limits the scan to the first N servers.
$CertScanReportRoot   = Join-Path -Path $OutputRoot -ChildPath 'Scan'     # CSV listing / report output directory.
$CertScanRetainCount  = 2                                                 # Timestamped CSV listings to retain.
$CertScanLastTotalObjects = 0                                            # Runtime: computer objects discovered in the last enumeration.
$CertScanLastExcluded     = 0                                            # Runtime: objects dropped by exclusion patterns in the last enumeration.
# Wildcard patterns (case-insensitive) matched against each discovered
# computer's short name; any match excludes that server from the scan.
$CertScanExcludePatterns = @(
    'VMHV*'                                                               # Begins with VMHV.
    'HVA*'                                                                # Begins with HVA.
    'VMRDS*'                                                              # Begins with VMRDS.
    'VMCTX*'                                                              # Begins with VMCTX
    'IT*'                                                                 # Begins with IT.
    '*CLU*'                                                               # Ends in CLU (CLU then optional node suffix, e.g. *CLU01).
    'DBL*'                                                                # Begins with DBL.
    'TD*'                                                                 # Begins with TD.
)

# --- Scan music (menu option 6) ---
# Frivolity for the domain certificate-expiry scan: a MIDI file is looped on a
# background runspace while the scan runs and silenced the moment it finishes,
# just before the expiring-certificate list is shown. Playback is best-effort
# only; a missing file or absent device is warned and the scan proceeds. The
# file is resolved relative to the script directory (matching the standalone
# IpanemaMID.ps1 layout). Set $EnableScanMusic to $false to disable entirely.
# $ScanMusicMaxPlays caps how many times the MIDI plays through; if the scan
# finishes first, playback is stopped at that point instead. Set it to 0 to
# loop until the scan completes (the pre-3.18 behavior).
$EnableScanMusic       = $false
$ScanMusicRelativePath = 'MIDI\The-Girl-From-Ipanema-DeptStore.mid'   # MIDI under <script>\MIDI.
$ScanMusicMciAlias     = 'certeratorscanmidi'                         # MCI sequencer alias for playback.
$ScanMusicMaxPlays     = 5                                            # Max MIDI plays before auto-stop; 0 = loop until the scan ends.

# --- 45-Day Certificate Expiration Report (menu option 7) ---
# Self-contained AD-discovery + parallel WinRM scan ported from
# CertificateExpiryReport.ps1. Server computer objects are discovered by
# name pattern, each reachable server's LocalMachine\My store is read over
# WinRM across a throttled RunspacePool, and an HTML body (no attachments)
# is emailed listing UH-issued Server-authentication certificates expiring
# within the threshold. The expected-issuer string flags UH-issued certs.
$ExpiryReportDaysThreshold    = 45                                 # Expiry window (days) for the report.
$ExpiryReportThrottleLimit    = 20                                 # Maximum concurrent scan runspaces.
$ExpiryReportStorePath        = 'Cert:\LocalMachine\My'           # Certificate store read on each server.
$ExpiryReportExpectedIssuer   = 'University Hospitals Sub CA 3'     # Issuer CN that marks a UH-issued certificate.
$ExpiryReportProgressActivity = 'Scanning Certificates'            # Write-Progress activity label.
$ExpiryReportMachinesOUBase   = 'OU=Machines,DC=uhhs,DC=com'       # Base OU for the sub-OU exclusions below.
# Computer objects under any of these sub-OUs of $ExpiryReportMachinesOUBase
# (and any OUs nested beneath them) are skipped during discovery.
$ExpiryReportExcludedSubOUs   = @('CTX', 'CTX-Test', 'ThinClients', 'VDI', 'Workstations')
# Additional OU subtrees to exclude, expressed as full distinguished names.
$ExpiryReportExcludedOUPaths  = @('OU=zMaintenance,DC=uhhs,DC=com')

# ============================================================
# REGION: LOGGING FUNCTIONS
# ============================================================

function Write-Log
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Message,

        [string]$Tag = 'INFO '
    )

    $Timestamp = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'
    $Entry     = '{0} [{1}] {2}' -f $Timestamp, $Tag, $Message

    try
    {
        Add-Content -LiteralPath $script:LogFile -Value $Entry -Encoding UTF8 -ErrorAction Stop
    }
    catch
    {
        Write-Host ('[ERROR] Unable to write to log file {0}: {1}' -f $script:LogFile, $_.Exception.Message) -ForegroundColor Red
    }
}

function Write-InfoMsg
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    Write-Host ('[INFO ] {0}' -f $Message) -ForegroundColor $script:LevelColors['INFO ']
    Write-Log -Message $Message -Tag 'INFO '
}

function Write-SuccessMsg
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    Write-Host ('[OK   ] {0}' -f $Message) -ForegroundColor $script:LevelColors['OK   ']
    Write-Log -Message $Message -Tag 'OK   '
}

function Write-WarnMsg
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    Write-Host ('[WARN ] {0}' -f $Message) -ForegroundColor $script:LevelColors['WARN ']
    Write-Log -Message $Message -Tag 'WARN '
}

function Write-ErrorMsg
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    Write-Host ('[ERROR] {0}' -f $Message) -ForegroundColor $script:LevelColors['ERROR']
    Write-Log -Message $Message -Tag 'ERROR'
}

function Write-DryRunMsg
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    Write-Host ('[DRYRUN] {0}' -f $Message) -ForegroundColor $script:LevelColors['DRYRUN']
    Write-Log -Message $Message -Tag 'DRYRUN'
}

function Write-BufferedEntry
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Tag,

        [Parameter(Mandatory = $true)]
        [string]$Message
    )

    switch ($Tag)
    {
        'OK   '  { Write-SuccessMsg $Message }
        'WARN '  { Write-WarnMsg    $Message }
        'ERROR'  { Write-ErrorMsg   $Message }
        'DRYRUN' { Write-DryRunMsg  $Message }
        default  { Write-InfoMsg    $Message }
    }
}

# ============================================================
# REGION: HELPER FUNCTIONS
# ============================================================

function Get-EmailSubject
{
    $DateStamp = Get-Date -Format 'MM-dd-yyyy'
    return ('{0} - {1}' -f $script:ScriptName, $DateStamp)
}

function Initialize-Logging
{
    foreach ($Dir in @($script:OutputRoot, $script:LogRoot))
    {
        if (-not (Test-Path -LiteralPath $Dir))
        {
            $null = New-Item -Path $Dir -ItemType Directory -Force
        }
    }

    Write-InfoMsg ('{0} started on {1}' -f $script:ScriptName, $script:FriendlyDate)
    Write-InfoMsg ('Log file: {0}' -f $script:LogFile)

    if ($script:DryRun)
    {
        Write-DryRunMsg 'DryRun mode is ENABLED. No files will be written, nothing will be submitted, and no remote operations will run.'
    }
}

# ============================================================
# REGION: Email Body Logo
# ============================================================

function New-EmailBodyLogoResource
{
    if (-not $EmailBodyLogoEnabled)
    {
        return $null
    }

    if ([string]::IsNullOrWhiteSpace($EmailBodyLogoBase64))
    {
        Write-WarnMsg "Email body logo enabled but no Base64 data present; skipping inline image."
        return $null
    }

    $LogoBytes    = [System.Convert]::FromBase64String($EmailBodyLogoBase64)
    $LogoStream   = New-Object System.IO.MemoryStream (, $LogoBytes)
    $LogoResource = New-Object System.Net.Mail.LinkedResource ($LogoStream, 'image/jpeg')

    $LogoResource.ContentId        = $EmailBodyLogoContentId
    $LogoResource.TransferEncoding = [System.Net.Mime.TransferEncoding]::Base64

    return $LogoResource
}

function Get-EmailBodyLogoHtml
{
    if (-not $EmailBodyLogoEnabled)
    {
        return ''
    }

    if ([string]::IsNullOrWhiteSpace($EmailBodyLogoBase64))
    {
        return ''
    }

    $LogoHtml = @"
<img src="cid:${EmailBodyLogoContentId}" width="$EmailBodyLogoWidth" height="$EmailBodyLogoHeight" alt="Certerator" style="display:block; border:0; outline:none; text-decoration:none;" />
"@

    return $LogoHtml
}

function Test-Prerequisites
{
    $AllOk = $true

    if (Test-Path -LiteralPath $script:OpenSSLPath)
    {
        Write-SuccessMsg ('OpenSSL found: {0}' -f $script:OpenSSLPath)
    }
    else
    {
        Write-ErrorMsg ('OpenSSL not found at {0}. Update $OpenSSLPath in the VARIABLES region.' -f $script:OpenSSLPath)
        $AllOk = $false
    }

    $CertReq = (Get-Command -Name 'certreq.exe' -ErrorAction SilentlyContinue).Source
    if ($CertReq)
    {
        Write-SuccessMsg ('certreq.exe found: {0}' -f $CertReq)
    }
    else
    {
        Write-ErrorMsg 'certreq.exe was not found in PATH. Windows PKI client tools are required.'
        $AllOk = $false
    }

    if ([string]::IsNullOrWhiteSpace($script:CAConfig))
    {
        Write-WarnMsg 'No CA configuration is set in the VARIABLES region.'
        $Entered = Read-Host 'Enter the issuing CA config string ("CAHost\CA Common Name")'
        if ([string]::IsNullOrWhiteSpace($Entered))
        {
            Write-ErrorMsg 'A CA configuration string is required to submit requests.'
            $AllOk = $false
        }
        else
        {
            $script:CAConfig = $Entered.Trim()
            Write-InfoMsg ('CA configuration set to: {0}' -f $script:CAConfig)
        }
    }
    else
    {
        Write-InfoMsg ('CA configuration: {0}' -f $script:CAConfig)
    }

    if ($script:CAChainFile -ne '' -and -not (Test-Path -LiteralPath $script:CAChainFile))
    {
        Write-WarnMsg ('Configured $CAChainFile not found: {0}. Falling back to .NET chain build.' -f $script:CAChainFile)
    }

    return $AllOk
}

function Read-DelimitedInput
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Prompt
    )

    $Raw = Read-Host $Prompt

    if ([string]::IsNullOrWhiteSpace($Raw))
    {
        return @()
    }

    $Items = $Raw -split '[,;]' |
        ForEach-Object { $_.Trim() } |
        Where-Object { $_ -ne '' }

    return @($Items)
}

function Get-ShortNameFromValue
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Value
    )

    $Trimmed = $Value.Trim()
    if ($Trimmed -match '\.')
    {
        return ($Trimmed -split '\.')[0]
    }

    return $Trimmed
}

function Read-WithDefault
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Prompt,

        [string]$Default = ''
    )

    $Suffix = if ([string]::IsNullOrWhiteSpace($Default)) { '' } else { (' [{0}]' -f $Default) }
    $Raw    = Read-Host (('{0}{1}' -f $Prompt, $Suffix))

    if ([string]::IsNullOrWhiteSpace($Raw))
    {
        return $Default
    }

    return $Raw.Trim()
}

function Read-PfxFilePassword
{
    $Secure = Read-Host -Prompt 'Enter the password for the PFX file' -AsSecureString

    if (-not $Secure -or $Secure.Length -eq 0)
    {
        Write-WarnMsg 'No password was entered; attempting to open the PFX with an empty password.'
        return (New-Object System.Security.SecureString)
    }

    return $Secure
}

function Test-RemoteStageEnabled
{
    return ($script:DeployToRemote -or $script:BindIis -or $script:VerifyDeployment)
}

function Test-CurrentUserIsSA
{
    $Identity = ''

    try
    {
        $Identity = (& whoami 2>$null | Select-Object -First 1)
    }
    catch
    {
        $Identity = ''
    }

    if ([string]::IsNullOrWhiteSpace($Identity))
    {
        $Identity = ('{0}\{1}' -f $env:USERDOMAIN, $env:USERNAME)
    }

    $Identity = $Identity.Trim()
    $UserPart = if ($Identity.Contains('\')) { ($Identity -split '\\')[-1] } else { $Identity }
    $IsSA     = ($UserPart -match '(?i)-sa$')

    return [PSCustomObject]@{
        Identity = $Identity
        UserPart = $UserPart
        IsSA     = $IsSA
    }
}

function Request-RemoteCredential
{
    if ($script:SACred -or $script:UseCurrentIdentity)
    {
        return $true
    }

    # Bypass the credential prompt when the interactive user is already logged
    # on under an -sa account; remote stages then run under the current logon
    # via integrated Windows authentication.
    $Current = Test-CurrentUserIsSA
    if ($Current.IsSA)
    {
        Write-InfoMsg ('Current logon is {0}, which appears to be an -sa account.' -f $Current.Identity)
        $Answer = Read-Host 'Use this logon for remote operations and skip the credential prompt? (Y/N) [Y]'

        if ([string]::IsNullOrWhiteSpace($Answer) -or $Answer.Trim() -match '(?i)^y')
        {
            $script:UseCurrentIdentity = $true
            Write-SuccessMsg ('Remote operations will run as the current logon: {0}' -f $Current.Identity)
            return $true
        }

        Write-InfoMsg 'Current logon will not be used; prompting for an -sa credential instead.'
    }

    Write-InfoMsg 'Remote operations are enabled; an -sa credential is required.'
    $Cred = Get-Credential -Message 'Enter your -sa account credentials (e.g. DOMAIN\jaltoma1-sa)'

    if (-not $Cred)
    {
        Write-ErrorMsg 'No credential provided. Remote stages cannot run.'
        return $false
    }

    $script:SACred = $Cred
    Write-SuccessMsg ('Credential captured for: {0}' -f $Cred.UserName)
    return $true
}

function Request-PfxPassword
{
    if (-not [string]::IsNullOrWhiteSpace($script:PfxPlain))
    {
        return $true
    }

    if (-not [string]::IsNullOrWhiteSpace($script:PFXPassword))
    {
        $script:PfxPlain = $script:PFXPassword
        return $true
    }

    Write-InfoMsg 'A PFX export password is required.'
    $Secure = Read-Host -Prompt 'Enter the PFX export password' -AsSecureString

    if (-not $Secure -or $Secure.Length -eq 0)
    {
        Write-ErrorMsg 'No PFX password provided. PFX export cannot run.'
        return $false
    }

    $Bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($Secure)
    try
    {
        $script:PfxPlain = [System.Runtime.InteropServices.Marshal]::PtrToStringBSTR($Bstr)
    }
    finally
    {
        [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($Bstr)
    }

    Write-SuccessMsg 'PFX password captured.'
    return $true
}

function Read-RemoteInstallChoice
{
    Write-Host ''
    Write-Host '----- Certificate Installation -----' -ForegroundColor Cyan
    Write-Host '  1. Install remotely on the target server(s) over WinRM' -ForegroundColor White
    Write-Host '  2. Keep the new certificate stored in the local path only' -ForegroundColor White
    Write-Host '------------------------------------' -ForegroundColor Cyan

    while ($true)
    {
        $Choice = Read-Host 'Select an installation option [2]'

        if ([string]::IsNullOrWhiteSpace($Choice))
        {
            $Choice = '2'
        }

        switch ($Choice.Trim())
        {
            '1'
            {
                return $true
            }

            '2'
            {
                return $false
            }

            default
            {
                Write-WarnMsg 'Invalid selection. Choose 1 or 2.'
            }
        }
    }
}

function Test-ServerReachable
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$WorkItems
    )

    $Reachable = [System.Collections.Generic.List[PSCustomObject]]::new()

    foreach ($Item in $WorkItems)
    {
        $Fqdn = '{0}.{1}' -f $Item.ShortName, $script:PrimaryDomain
        $Ok   = Test-WSMan -ComputerName $Fqdn -ErrorAction SilentlyContinue

        if ($Ok)
        {
            Write-SuccessMsg ('WinRM reachable: {0}' -f $Fqdn)
            $Reachable.Add($Item)
        }
        else
        {
            Write-WarnMsg ('{0} is not a valid destination at this time.' -f $Fqdn)
            Write-InfoMsg 'Remote stages will be skipped for this destination'
            $Item | Add-Member -NotePropertyName 'RemoteSkipped' -NotePropertyValue $true -Force
            $Reachable.Add($Item)
        }
    }

    return $Reachable
}

function Test-CertScanExcluded
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Name
    )

    foreach ($Pattern in $script:CertScanExcludePatterns)
    {
        if ([string]::IsNullOrWhiteSpace($Pattern))
        {
            continue
        }

        if ($Name -like $Pattern)
        {
            return $true
        }
    }

    return $false
}

function Get-DomainServerList
{
    if (-not (Get-Module -ListAvailable -Name ActiveDirectory))
    {
        Write-ErrorMsg 'The ActiveDirectory module is not available on this host. Install RSAT AD PowerShell to use the domain scan.'
        return [System.Collections.Generic.List[PSCustomObject]]::new()
    }

    try
    {
        Import-Module ActiveDirectory -ErrorAction Stop
    }
    catch
    {
        Write-ErrorMsg ('Failed to import the ActiveDirectory module: {0}' -f $_.Exception.Message)
        return [System.Collections.Generic.List[PSCustomObject]]::new()
    }

    $QuerySplat = @{
        Filter      = $script:CertScanServerFilter
        Server      = $script:CertScanADServer
        Properties  = @('DNSHostName', 'OperatingSystem')
        ErrorAction = 'Stop'
    }

    if (-not [string]::IsNullOrWhiteSpace($script:CertScanSearchBase))
    {
        $QuerySplat['SearchBase'] = $script:CertScanSearchBase
    }

    Write-InfoMsg ('Querying {0} for server computer objects...' -f $script:CertScanADServer)

    try
    {
        $Computers = Get-ADComputer @QuerySplat
    }
    catch
    {
        Write-ErrorMsg ('Active Directory query failed: {0}' -f $_.Exception.Message)
        return [System.Collections.Generic.List[PSCustomObject]]::new()
    }

    $Servers  = [System.Collections.Generic.List[PSCustomObject]]::new()
    $Excluded = 0

    $ActivePatterns = @($script:CertScanExcludePatterns | Where-Object { -not [string]::IsNullOrWhiteSpace($_) })
    if ($ActivePatterns.Count -gt 0)
    {
        Write-InfoMsg ('Applying {0} exclusion pattern(s): {1}' -f $ActivePatterns.Count, ($ActivePatterns -join ', '))
    }

    foreach ($Computer in $Computers)
    {
        $Short = $Computer.Name

        if (Test-CertScanExcluded -Name $Short)
        {
            $Excluded++
            continue
        }

        $Fqdn  = if (-not [string]::IsNullOrWhiteSpace($Computer.DNSHostName)) { $Computer.DNSHostName } else { '{0}.{1}' -f $Short, $script:PrimaryDomain }

        $Servers.Add([PSCustomObject]@{
            ShortName = $Short
            Fqdn      = $Fqdn
        })
    }

    if ($Excluded -gt 0)
    {
        Write-InfoMsg ('Excluded {0} server(s) matching the configured exclusion patterns.' -f $Excluded)
    }

    $script:CertScanLastTotalObjects = @($Computers).Count
    $script:CertScanLastExcluded     = $Excluded

    Write-SuccessMsg ('{0} server computer object(s) remain after exclusions ({1} discovered, {2} excluded).' -f $Servers.Count, $script:CertScanLastTotalObjects, $Excluded)

    if ($script:CertScanMaxServers -gt 0 -and $Servers.Count -gt $script:CertScanMaxServers)
    {
        $Capped = [System.Collections.Generic.List[PSCustomObject]]::new()
        for ($i = 0; $i -lt $script:CertScanMaxServers; $i++)
        {
            $Capped.Add($Servers[$i])
        }

        Write-InfoMsg ('Limiting the scan to the first {0} server(s) per the $CertScanMaxServers cap.' -f $script:CertScanMaxServers)
        return $Capped
    }

    return $Servers
}

function Limit-TimestampedFiles
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Directory,

        [Parameter(Mandatory = $true)]
        [string]$Filter,

        [Parameter(Mandatory = $true)]
        [int]$KeepCount
    )

    if (-not (Test-Path -LiteralPath $Directory))
    {
        return
    }

    $Files = Get-ChildItem -LiteralPath $Directory -Filter $Filter -File -ErrorAction SilentlyContinue |
        Sort-Object -Property LastWriteTime -Descending

    if ($Files.Count -le $KeepCount)
    {
        return
    }

    $ToRemove = $Files | Select-Object -Skip $KeepCount
    foreach ($Old in $ToRemove)
    {
        try
        {
            Remove-Item -LiteralPath $Old.FullName -Force -ErrorAction Stop
            Write-InfoMsg ('Removed old listing: {0}' -f $Old.Name)
        }
        catch
        {
            Write-WarnMsg ('Could not remove old listing {0}: {1}' -f $Old.Name, $_.Exception.Message)
        }
    }
}

# ============================================================
# REGION: SAN AND CONFIG FUNCTIONS
# ============================================================

function Build-SanList
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$ShortName,

        [string[]]$ExtraDns = @(),

        [string[]]$ExtraIp = @()
    )

    $PrimaryFqdn   = '{0}.{1}' -f $ShortName, $script:PrimaryDomain
    $AlternateFqdn = '{0}.{1}' -f $ShortName, $script:AlternateDomain

    $DnsNames = [System.Collections.Generic.List[string]]::new()
    foreach ($Name in @($PrimaryFqdn, $AlternateFqdn, $ShortName) + $ExtraDns)
    {
        if ([string]::IsNullOrWhiteSpace($Name))
        {
            continue
        }

        $Clean = $Name.Trim()
        if ($Clean -ne '' -and -not $DnsNames.Contains($Clean))
        {
            $DnsNames.Add($Clean)
        }
    }

    $IpAddresses = [System.Collections.Generic.List[string]]::new()
    foreach ($Ip in $ExtraIp)
    {
        if ([string]::IsNullOrWhiteSpace($Ip))
        {
            continue
        }

        $Clean = $Ip.Trim()
        if ($Clean -ne '' -and -not $IpAddresses.Contains($Clean))
        {
            $IpAddresses.Add($Clean)
        }
    }

    return [PSCustomObject]@{
        CommonName  = $PrimaryFqdn
        DnsNames    = $DnsNames
        IpAddresses = $IpAddresses
    }
}

# ============================================================
# REGION: CSR READING (RENEWAL)
# ============================================================

function Read-ExistingCsr
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$CsrPath
    )

    $ReadArgs = @(
        'req'
        '-in', $CsrPath
        '-noout'
        '-text'
    )

    $Text = & $script:OpenSSLPath @ReadArgs 2>&1
    if ($LASTEXITCODE -ne 0)
    {
        Write-ErrorMsg ('OpenSSL could not parse the CSR {0}.' -f $CsrPath)
        return $null
    }

    $Joined = ($Text | Out-String)

    $CommonName = $null
    $CnMatch = [regex]::Match($Joined, 'CN\s*=\s*([^,\r\n]+)')
    if ($CnMatch.Success)
    {
        $CommonName = $CnMatch.Groups[1].Value.Trim()
    }

    $DnsNames    = [System.Collections.Generic.List[string]]::new()
    $IpAddresses = [System.Collections.Generic.List[string]]::new()

    foreach ($DnsHit in [regex]::Matches($Joined, 'DNS:([^,\s]+)'))
    {
        $Value = $DnsHit.Groups[1].Value.Trim()
        if ($Value -ne '' -and -not $DnsNames.Contains($Value))
        {
            $DnsNames.Add($Value)
        }
    }

    foreach ($IpHit in [regex]::Matches($Joined, 'IP Address:([^,\s]+)'))
    {
        $Value = $IpHit.Groups[1].Value.Trim()
        if ($Value -ne '' -and -not $IpAddresses.Contains($Value))
        {
            $IpAddresses.Add($Value)
        }
    }

    if (-not $CommonName)
    {
        Write-ErrorMsg ('No Common Name (CN) was found in {0}.' -f $CsrPath)
        return $null
    }

    Write-InfoMsg ('Parsed CSR CN: {0}' -f $CommonName)
    Write-InfoMsg ('Parsed DNS SANs: {0}' -f (($DnsNames -join ', ')))
    if ($IpAddresses.Count -gt 0)
    {
        Write-InfoMsg ('Parsed IP SANs: {0}' -f (($IpAddresses -join ', ')))
    }

    return [PSCustomObject]@{
        CommonName  = $CommonName
        DnsNames    = $DnsNames
        IpAddresses = $IpAddresses
    }
}

# ============================================================
# REGION: PFX INSPECTION
# ============================================================

function Import-PfxCertificateObject
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$PfxPath,

        [Parameter(Mandatory = $true)]
        [System.Security.SecureString]$Password
    )

    $Flags = [System.Security.Cryptography.X509Certificates.X509KeyStorageFlags]::Exportable

    try
    {
        $Cert = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2 -ArgumentList @($PfxPath, $Password, $Flags)
        Write-SuccessMsg ('PFX loaded: {0}' -f $PfxPath)
        return $Cert
    }
    catch
    {
        Write-ErrorMsg ('Unable to open PFX {0}: {1}' -f $PfxPath, $_.Exception.Message)
        Write-InfoMsg  'Verify the file path and the password and try again.'
        return $null
    }
}

function ConvertFrom-X500Name
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Security.Cryptography.X509Certificates.X500DistinguishedName]$Name
    )

    $Fields = [ordered]@{}

    $Formatted = $Name.Format($true)
    $Lines     = $Formatted -split '\r?\n' |
        ForEach-Object { $_.Trim() } |
        Where-Object { $_ -ne '' }

    foreach ($Line in $Lines)
    {
        $SplitAt = $Line.IndexOf('=')
        if ($SplitAt -lt 1)
        {
            continue
        }

        $Key   = $Line.Substring(0, $SplitAt).Trim().ToUpperInvariant()
        $Value = $Line.Substring($SplitAt + 1).Trim()

        if (-not $Fields.Contains($Key))
        {
            $Fields[$Key] = $Value
        }
    }

    return $Fields
}

function Get-SubjectFieldValue
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Specialized.OrderedDictionary]$Fields,

        [Parameter(Mandatory = $true)]
        [string[]]$Keys,

        [string]$Default = ''
    )

    foreach ($Key in $Keys)
    {
        $Upper = $Key.ToUpperInvariant()
        if ($Fields.Contains($Upper) -and -not [string]::IsNullOrWhiteSpace([string]$Fields[$Upper]))
        {
            return [string]$Fields[$Upper]
        }
    }

    return $Default
}

function Get-CertificateTemplateName
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Security.Cryptography.X509Certificates.X509Certificate2]$Cert
    )

    foreach ($Oid in @($script:OidTemplateInfo, $script:OidTemplateNameV1))
    {
        $Ext = $Cert.Extensions |
            Where-Object { $_.Oid.Value -eq $Oid } |
            Select-Object -First 1

        if ($Ext)
        {
            $Formatted = ($Ext.Format($true) -split '\r?\n' |
                ForEach-Object { $_.Trim() } |
                Where-Object { $_ -ne '' }) -join '; '

            $NameMatch = [regex]::Match($Formatted, 'Template=([^(;\r\n]+)')
            if ($NameMatch.Success)
            {
                return $NameMatch.Groups[1].Value.Trim()
            }

            return $Formatted
        }
    }

    return 'Not present'
}

function Get-CertificateSan
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Security.Cryptography.X509Certificates.X509Certificate2]$Cert
    )

    $DnsNames    = [System.Collections.Generic.List[string]]::new()
    $IpAddresses = [System.Collections.Generic.List[string]]::new()

    $Ext = $Cert.Extensions |
        Where-Object { $_.Oid.Value -eq $script:OidSubjectAltName } |
        Select-Object -First 1

    if ($Ext)
    {
        $Formatted = $Ext.Format($true)

        foreach ($DnsHit in [regex]::Matches($Formatted, 'DNS Name=([^,\r\n]+)'))
        {
            $Value = $DnsHit.Groups[1].Value.Trim()
            if ($Value -ne '' -and -not $DnsNames.Contains($Value))
            {
                $DnsNames.Add($Value)
            }
        }

        foreach ($IpHit in [regex]::Matches($Formatted, 'IP Address=([^,\r\n]+)'))
        {
            $Value = $IpHit.Groups[1].Value.Trim()
            if ($Value -ne '' -and -not $IpAddresses.Contains($Value))
            {
                $IpAddresses.Add($Value)
            }
        }
    }

    return [PSCustomObject]@{
        DnsNames    = $DnsNames
        IpAddresses = $IpAddresses
    }
}

function Export-CerAndCrt
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Security.Cryptography.X509Certificates.X509Certificate2]$Cert,

        [Parameter(Mandatory = $true)]
        [string]$BaseName
    )

    if (-not (Test-Path -LiteralPath $script:InspectRoot))
    {
        $null = New-Item -Path $script:InspectRoot -ItemType Directory -Force
    }

    $CerPath = Join-Path -Path $script:InspectRoot -ChildPath ('{0}.cer' -f $BaseName)
    $CrtPath = Join-Path -Path $script:InspectRoot -ChildPath ('{0}.crt' -f $BaseName)

    $DerBytes = $Cert.Export([System.Security.Cryptography.X509Certificates.X509ContentType]::Cert)
    [System.IO.File]::WriteAllBytes($CerPath, $DerBytes)
    Write-SuccessMsg ('DER certificate written: {0}' -f $CerPath)

    $B64    = [Convert]::ToBase64String($Cert.RawData, 'InsertLineBreaks')
    $PemTxt = '-----BEGIN CERTIFICATE-----' + [Environment]::NewLine + $B64 + [Environment]::NewLine + '-----END CERTIFICATE-----'
    $PemTxt | Out-File -FilePath $CrtPath -Encoding ASCII -Force
    Write-SuccessMsg ('PEM certificate written: {0}' -f $CrtPath)

    return [PSCustomObject]@{
        CerPath = $CerPath
        CrtPath = $CrtPath
    }
}

function Show-CertificateDetails
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Security.Cryptography.X509Certificates.X509Certificate2]$Cert
    )

    $SubjectFields = ConvertFrom-X500Name -Name $Cert.SubjectName
    $IssuerFields  = ConvertFrom-X500Name -Name $Cert.IssuerName
    $Template      = Get-CertificateTemplateName -Cert $Cert
    $San           = Get-CertificateSan -Cert $Cert

    $CommonName   = Get-SubjectFieldValue -Fields $SubjectFields -Keys @('CN')               -Default 'N/A'
    $Country      = Get-SubjectFieldValue -Fields $SubjectFields -Keys @('C')                -Default ''
    $State        = Get-SubjectFieldValue -Fields $SubjectFields -Keys @('S', 'ST')          -Default ''
    $Locality     = Get-SubjectFieldValue -Fields $SubjectFields -Keys @('L')                -Default ''
    $Organization = Get-SubjectFieldValue -Fields $SubjectFields -Keys @('O')                -Default ''
    $OrgUnit      = Get-SubjectFieldValue -Fields $SubjectFields -Keys @('OU')               -Default ''
    $Email        = Get-SubjectFieldValue -Fields $SubjectFields -Keys @('E', 'EMAILADDRESS') -Default ''
    $IssuerCn     = Get-SubjectFieldValue -Fields $IssuerFields  -Keys @('CN')               -Default $Cert.Issuer

    Write-Host ''
    Write-Host '===================== Certificate Details =====================' -ForegroundColor Cyan

    Write-InfoMsg ('Template            : {0}' -f $Template)
    Write-InfoMsg ('Common Name (CN)    : {0}' -f $CommonName)
    Write-InfoMsg ('Country (C)         : {0}' -f $Country)
    Write-InfoMsg ('State / Province (S): {0}' -f $State)
    Write-InfoMsg ('Locality (L)        : {0}' -f $Locality)
    Write-InfoMsg ('Organization (O)    : {0}' -f $Organization)
    Write-InfoMsg ('Org. Unit (OU)      : {0}' -f $OrgUnit)

    if (-not [string]::IsNullOrWhiteSpace($Email))
    {
        Write-InfoMsg ('Email (E)           : {0}' -f $Email)
    }

    Write-InfoMsg ('Issuer CN           : {0}' -f $IssuerCn)
    Write-InfoMsg ('Serial Number       : {0}' -f $Cert.SerialNumber)
    Write-InfoMsg ('Thumbprint          : {0}' -f $Cert.Thumbprint)
    Write-InfoMsg ('Valid From          : {0}' -f $Cert.NotBefore)
    Write-InfoMsg ('Valid To            : {0}' -f $Cert.NotAfter)

    if ($San.DnsNames.Count -gt 0)
    {
        Write-InfoMsg ('DNS SANs            : {0}' -f ($San.DnsNames -join ', '))
    }
    else
    {
        Write-InfoMsg 'DNS SANs            : (none)'
    }

    if ($San.IpAddresses.Count -gt 0)
    {
        Write-InfoMsg ('IP SANs             : {0}' -f ($San.IpAddresses -join ', '))
    }
    else
    {
        Write-InfoMsg 'IP SANs             : (none)'
    }

    Write-Host '===============================================================' -ForegroundColor Cyan

    return [PSCustomObject]@{
        Template     = $Template
        CommonName   = $CommonName
        Country      = $Country
        State        = $State
        Locality     = $Locality
        Organization = $Organization
        OrgUnit      = $OrgUnit
        Email        = $Email
        DnsNames     = $San.DnsNames
        IpAddresses  = $San.IpAddresses
    }
}

# ============================================================
# REGION: SERVER PIPELINE (WORKER)
# ============================================================

# Self-contained per-server pipeline. It must not call script-scope logging
# helpers or touch the shared log file, because it also runs inside isolated
# RunspacePool threads. Instead it buffers structured log entries (Tag +
# Message) into the returned result; the main thread replays them through the
# standard Write-*Msg helpers so output still reaches file and console.
$ServerWorker = {
    param
    (
        [PSCustomObject]$WorkItem,
        [hashtable]$Config,
        [System.Management.Automation.PSCredential]$SACred,
        [string]$PfxPlain
    )

    $LogEntries = [System.Collections.Generic.List[object]]::new()

    function Add-WorkerLog
    {
        param
        (
            [string]$Message,
            [string]$Tag = 'INFO '
        )

        $LogEntries.Add([PSCustomObject]@{ Tag = $Tag; Message = $Message })
    }

    $ShortName     = $WorkItem.ShortName
    $CommonName    = $WorkItem.CommonName
    $DnsNames      = $WorkItem.DnsNames
    $IpAddresses   = $WorkItem.IpAddresses
    $Template      = $WorkItem.Template
    $RunMode       = $WorkItem.RunMode
    $RemoteSkipped = ($WorkItem.PSObject.Properties.Name -contains 'RemoteSkipped' -and $WorkItem.RemoteSkipped)

    $PrimaryFqdn = '{0}.{1}' -f $ShortName, $Config.PrimaryDomain
    $ServerDir   = Join-Path -Path $Config.OutputRoot -ChildPath $ShortName

    $ConfigFile = Join-Path -Path $ServerDir -ChildPath ('{0}.cnf' -f $ShortName)
    $KeyFile    = Join-Path -Path $ServerDir -ChildPath ('{0}.key' -f $ShortName)
    $PemFile    = Join-Path -Path $ServerDir -ChildPath ('{0}.pem' -f $ShortName)
    $CsrFile    = Join-Path -Path $ServerDir -ChildPath ('{0}.csr' -f $ShortName)
    $CerFile    = Join-Path -Path $ServerDir -ChildPath ('{0}.cer' -f $ShortName)
    $CerPemFile = Join-Path -Path $ServerDir -ChildPath ('{0}-cert.pem' -f $ShortName)
    $ChainFile  = Join-Path -Path $ServerDir -ChildPath ('{0}-chain.pem' -f $ShortName)
    $PfxFile    = Join-Path -Path $ServerDir -ChildPath ('{0}.pfx' -f $ShortName)
    $ErrLog     = Join-Path -Path $ServerDir -ChildPath ('{0}-openssl.log' -f $ShortName)
    $SubmitLog  = Join-Path -Path $ServerDir -ChildPath ('{0}-certreq.log' -f $ShortName)

    $Result = [PSCustomObject]@{
        Server          = $ShortName
        CommonName      = $CommonName
        RunMode         = $RunMode
        Template        = $Template
        DnsSans         = ($DnsNames -join ', ')
        IpSans          = ($IpAddresses -join ', ')
        CsrStatus       = 'Pending'
        SubmitStatus    = 'Skipped'
        RequestId       = 'N/A'
        ChainStatus     = 'Skipped'
        PfxStatus       = 'Skipped'
        RemoteDirStatus = 'Skipped'
        DeployStatus    = 'Skipped'
        IisBindStatus   = 'Skipped'
        VerifyStatus    = 'Skipped'
        Thumbprint      = 'N/A'
        LogEntries      = $LogEntries
    }

    Add-WorkerLog ('Processing {0} (CN: {1}, mode: {2})' -f $ShortName, $CommonName, $RunMode)

    if ($IpAddresses.Count -gt 0)
    {
        Add-WorkerLog 'IP SANs were supplied; some CA templates reject IP address SANs. Verify issuance.' 'WARN '
    }

    # ----- DryRun short-circuit -----
    if ($Config.DryRun)
    {
        Add-WorkerLog ('Would create config/key/CSR under {0}' -f $ServerDir) 'DRYRUN'
        Add-WorkerLog ('Would submit to CA {0} using template "{1}"' -f $Config.CAConfig, $Template) 'DRYRUN'
        if ($Config.ExportPfx)      { Add-WorkerLog 'Would build chain and export full-chain PFX.' 'DRYRUN' }
        if ($Config.DeployToRemote) { Add-WorkerLog ('Would deploy artifacts to {0} on {1}' -f $Config.RemoteCertDir, $PrimaryFqdn) 'DRYRUN' }
        if ($Config.BindIis)        { Add-WorkerLog ('Would import PFX and bind IIS {0}:{1} on {2}' -f $Config.IISSiteName, $Config.IISBindPort, $PrimaryFqdn) 'DRYRUN' }
        if ($Config.VerifyDeployment) { Add-WorkerLog 'Would verify deployed files and IIS binding.' 'DRYRUN' }

        $Result.CsrStatus    = 'DryRun'
        $Result.SubmitStatus = 'DryRun'
        return $Result
    }

    # ----- Ensure local server directory -----
    if (-not (Test-Path -LiteralPath $ServerDir))
    {
        $null = New-Item -Path $ServerDir -ItemType Directory -Force
    }

    # ----- Build OpenSSL config -----
    $SanLines = [System.Collections.Generic.List[string]]::new()
    $DnsIndex = 1
    foreach ($Dns in $DnsNames)
    {
        $SanLines.Add(('DNS.{0} = {1}' -f $DnsIndex, $Dns))
        $DnsIndex++
    }
    $IpIndex = 1
    foreach ($Ip in $IpAddresses)
    {
        $SanLines.Add(('IP.{0} = {1}' -f $IpIndex, $Ip))
        $IpIndex++
    }
    $SanBlock = $SanLines -join [Environment]::NewLine

    $ConfigText = @"
[req]
prompt             = no
default_md         = sha256
default_bits       = $($Config.KeyLength)
distinguished_name = dn
req_extensions     = v3_req

[dn]
C  = $($Config.Country)
ST = $($Config.State)
L  = $($Config.Locality)
O  = $($Config.Organization)
OU = $($Config.OrgUnit)
CN = $CommonName

[v3_req]
keyUsage           = critical, digitalSignature, keyEncipherment
extendedKeyUsage   = serverAuth
subjectAltName     = @alt_names

[alt_names]
$SanBlock
"@

    $ConfigText | Out-File -FilePath $ConfigFile -Encoding ASCII -Force
    Add-WorkerLog ('Config written: {0}' -f $ConfigFile)
    foreach ($Line in $SanLines)
    {
        Add-WorkerLog ('    {0}' -f $Line)
    }

    # ----- Generate key + CSR -----
    $OpenSslArgs = @(
        'req'
        '-new'
        '-newkey', ('rsa:{0}' -f $Config.KeyLength)
        '-nodes'
        '-keyout', $KeyFile
        '-out', $CsrFile
        '-config', $ConfigFile
    )

    $CsrProc = @{
        FilePath              = $Config.OpenSSLPath
        ArgumentList          = $OpenSslArgs
        NoNewWindow           = $true
        Wait                  = $true
        PassThru              = $true
        RedirectStandardError = $ErrLog
    }

    $Proc = Start-Process @CsrProc

    if ($Proc.ExitCode -ne 0 -or -not (Test-Path -LiteralPath $CsrFile))
    {
        Add-WorkerLog ('OpenSSL CSR generation failed (exit {0}). See {1}' -f $Proc.ExitCode, $ErrLog) 'ERROR'
        $Result.CsrStatus = 'Failed'
        return $Result
    }

    Add-WorkerLog ('CSR generated: {0}' -f $CsrFile) 'OK   '
    Add-WorkerLog ('Key generated: {0}' -f $KeyFile) 'OK   '
    $Result.CsrStatus = 'Success'

    # ----- Generate PKCS#1 .pem copy of the private key -----
    $PemArgs = @(
        'rsa'
        '-in', $KeyFile
        '-out', $PemFile
    )
    $PemProc = @{
        FilePath              = $Config.OpenSSLPath
        ArgumentList          = $PemArgs
        NoNewWindow           = $true
        Wait                  = $true
        PassThru              = $true
        RedirectStandardError = $ErrLog
    }
    $PemResult = Start-Process @PemProc
    if ($PemResult.ExitCode -eq 0)
    {
        Add-WorkerLog ('PEM key written: {0}' -f $PemFile) 'OK   '
    }
    else
    {
        Add-WorkerLog ('PKCS#1 PEM export failed (exit {0}).' -f $PemResult.ExitCode) 'WARN '
    }

    # ----- Submit CSR to CA -----
    Add-WorkerLog ('Submitting {0} to CA {1} (template: {2})' -f $CsrFile, $Config.CAConfig, $Template)

    $CertReqArgs = @(
        '-submit'
        '-config', $Config.CAConfig
        '-attrib', ('CertificateTemplate:{0}' -f $Template)
        $CsrFile
        $CerFile
    )

    $CertReqOutput = & certreq.exe @CertReqArgs 2>&1
    $CertReqExit   = $LASTEXITCODE
    $CertReqOutput | Out-File -FilePath $SubmitLog -Encoding UTF8 -Force

    $IdMatch = $CertReqOutput | Select-String -Pattern 'RequestId:\s*(\d+)' | Select-Object -First 1
    if ($IdMatch)
    {
        $Result.RequestId = $IdMatch.Matches[0].Groups[1].Value
    }

    if ($CertReqExit -ne 0 -or -not (Test-Path -LiteralPath $CerFile))
    {
        $CertReqText = ($CertReqOutput | Out-String)
        $IsPending   = ($CertReqText -match '(?i)pending|taken under submission') -or
                       ($CertReqExit -eq 0 -and $Result.RequestId -ne 'N/A')

        if ($IsPending)
        {
            Add-WorkerLog 'Certificate submitted to CA for Approval.  Checking in Pending Requests.'
            Add-WorkerLog ('See logfile:  {0}' -f $SubmitLog)
            $Result.SubmitStatus = ('Pending Approval (RequestId: {0})' -f $Result.RequestId)
        }
        else
        {
            Add-WorkerLog ('Submission did not return an issued certificate (exit {0}, RequestId: {1}). See {2}' -f $CertReqExit, $Result.RequestId, $SubmitLog) 'WARN '
            $Result.SubmitStatus = 'Failed'
        }

        return $Result
    }

    Add-WorkerLog ('Certificate issued: {0} (RequestId: {1})' -f $CerFile, $Result.RequestId) 'OK   '
    $Result.SubmitStatus = 'Issued'

    # ----- Load issued certificate (.NET) -----
    try
    {
        $Leaf = New-Object System.Security.Cryptography.X509Certificates.X509Certificate2 -ArgumentList $CerFile
        $Result.Thumbprint = $Leaf.Thumbprint
    }
    catch
    {
        Add-WorkerLog ('Unable to load issued certificate: {0}' -f $_.Exception.Message) 'ERROR'
        return $Result
    }

    # Write a PEM copy of the leaf for OpenSSL consumption.
    $LeafB64 = [Convert]::ToBase64String($Leaf.RawData, 'InsertLineBreaks')
    $LeafPem = '-----BEGIN CERTIFICATE-----' + [Environment]::NewLine + $LeafB64 + [Environment]::NewLine + '-----END CERTIFICATE-----'
    $LeafPem | Out-File -FilePath $CerPemFile -Encoding ASCII -Force

    # ----- Build issuing/root chain -----
    $HaveChain = $false
    if ($Config.ExportPfx)
    {
        if ($Config.CAChainFile -ne '' -and (Test-Path -LiteralPath $Config.CAChainFile))
        {
            Copy-Item -LiteralPath $Config.CAChainFile -Destination $ChainFile -Force
            $HaveChain = $true
            $Result.ChainStatus = 'From $CAChainFile'
            Add-WorkerLog ('Chain sourced from configured file: {0}' -f $Config.CAChainFile) 'OK   '
        }
        else
        {
            try
            {
                $Chain = New-Object System.Security.Cryptography.X509Certificates.X509Chain
                $Chain.ChainPolicy.RevocationMode = [System.Security.Cryptography.X509Certificates.X509RevocationMode]::NoCheck
                $null = $Chain.Build($Leaf)

                if ($Chain.ChainElements.Count -gt 1)
                {
                    $ChainSb = New-Object System.Text.StringBuilder
                    for ($i = 1; $i -lt $Chain.ChainElements.Count; $i++)
                    {
                        $ElementCert = $Chain.ChainElements[$i].Certificate
                        $ElementB64  = [Convert]::ToBase64String($ElementCert.RawData, 'InsertLineBreaks')
                        [void]$ChainSb.AppendLine('-----BEGIN CERTIFICATE-----')
                        [void]$ChainSb.AppendLine($ElementB64)
                        [void]$ChainSb.AppendLine('-----END CERTIFICATE-----')
                    }
                    $ChainSb.ToString() | Out-File -FilePath $ChainFile -Encoding ASCII -Force
                    $HaveChain = $true
                    $Result.ChainStatus = ('Built ({0} CA cert(s))' -f ($Chain.ChainElements.Count - 1))
                    Add-WorkerLog ('Chain built via .NET X509Chain: {0}' -f $ChainFile) 'OK   '
                }
                else
                {
                    $Result.ChainStatus = 'Leaf only (no chain resolved)'
                    Add-WorkerLog 'Chain could not be resolved beyond the leaf certificate.' 'WARN '
                }
            }
            catch
            {
                $Result.ChainStatus = ('Build failed: {0}' -f $_.Exception.Message)
                Add-WorkerLog ('Chain build failed: {0}' -f $_.Exception.Message) 'WARN '
            }
        }
    }

    # ----- Export full-chain PFX -----
    if ($Config.ExportPfx)
    {
        $EnvName = ('JEFFSPFXPW_{0}' -f $ShortName)
        Set-Item -Path ('Env:\{0}' -f $EnvName) -Value $PfxPlain

        $PfxArgs = [System.Collections.Generic.List[string]]::new()
        $PfxArgs.Add('pkcs12')
        $PfxArgs.Add('-export')
        $PfxArgs.Add('-inkey'); $PfxArgs.Add($KeyFile)
        $PfxArgs.Add('-in');    $PfxArgs.Add($CerPemFile)
        if ($HaveChain)
        {
            $PfxArgs.Add('-certfile'); $PfxArgs.Add($ChainFile)
        }
        $PfxArgs.Add('-out');     $PfxArgs.Add($PfxFile)
        $PfxArgs.Add('-name');    $PfxArgs.Add($CommonName)
        $PfxArgs.Add('-passout'); $PfxArgs.Add(('env:{0}' -f $EnvName))

        $PfxProc = @{
            FilePath              = $Config.OpenSSLPath
            ArgumentList          = $PfxArgs.ToArray()
            NoNewWindow           = $true
            Wait                  = $true
            PassThru              = $true
            RedirectStandardError = $ErrLog
        }

        $PfxResult = Start-Process @PfxProc
        Remove-Item -Path ('Env:\{0}' -f $EnvName) -ErrorAction SilentlyContinue

        if ($PfxResult.ExitCode -eq 0 -and (Test-Path -LiteralPath $PfxFile))
        {
            $Result.PfxStatus = if ($HaveChain) { 'Full-chain PFX' } else { 'Leaf-only PFX' }
            Add-WorkerLog ('PFX exported: {0}' -f $PfxFile) 'OK   '
        }
        else
        {
            $Result.PfxStatus = ('Failed (exit {0})' -f $PfxResult.ExitCode)
            Add-WorkerLog ('PFX export failed (exit {0}). See {1}' -f $PfxResult.ExitCode, $ErrLog) 'WARN '
        }
    }

    # ----- Remote operations (deploy / import / bind / verify) -----
    $WantRemote = ($Config.DeployToRemote -or $Config.BindIis -or $Config.VerifyDeployment)
    if (-not $WantRemote)
    {
        return $Result
    }

    if ($RemoteSkipped)
    {
        Add-WorkerLog ('Skipping remote stages — {0} was unreachable during pre-flight.' -f $PrimaryFqdn) 'WARN '
        $Result.RemoteDirStatus = 'Unreachable'
        $Result.DeployStatus    = 'Unreachable'
        $Result.IisBindStatus   = 'Unreachable'
        $Result.VerifyStatus    = 'Unreachable'
        return $Result
    }

    if (-not $SACred -and -not $Config.UseCurrentIdentity)
    {
        Add-WorkerLog 'No -sa credential available; remote stages skipped.' 'WARN '
        return $Result
    }

    $Session = $null
    try
    {
        if ($Config.UseCurrentIdentity)
        {
            $Session = New-PSSession -ComputerName $PrimaryFqdn -ErrorAction Stop
            Add-WorkerLog ('PSSession opened as current logon: {0}' -f $PrimaryFqdn) 'OK   '
        }
        else
        {
            $Session = New-PSSession -ComputerName $PrimaryFqdn -Credential $SACred -ErrorAction Stop
            Add-WorkerLog ('PSSession opened: {0}' -f $PrimaryFqdn) 'OK   '
        }
    }
    catch
    {
        Add-WorkerLog ('Failed to open PSSession to {0}: {1}' -f $PrimaryFqdn, $_.Exception.Message) 'ERROR'
        $Result.RemoteDirStatus = 'Session failed'
        return $Result
    }

    try
    {
        # --- Ensure remote certificate directory ---
        $DirResult = Invoke-Command -Session $Session -ScriptBlock {
            param($Dir)
            if (Test-Path -LiteralPath $Dir)
            {
                return 'Exists'
            }
            New-Item -Path $Dir -ItemType Directory -Force | Out-Null
            return 'Created'
        } -ArgumentList $Config.RemoteCertDir

        $Result.RemoteDirStatus = $DirResult
        Add-WorkerLog ('Remote {0}: {1}' -f $Config.RemoteCertDir, $DirResult) 'OK   '

        # --- Deploy artifacts ---
        if ($Config.DeployToRemote)
        {
            $FilesToCopy = @($KeyFile, $PemFile, $CerFile, $PfxFile) |
                Where-Object { Test-Path -LiteralPath $_ }

            Copy-Item -Path $FilesToCopy -Destination $Config.RemoteCertDir -ToSession $Session -Force -ErrorAction Stop
            $Result.DeployStatus = ('Copied {0} file(s)' -f $FilesToCopy.Count)
            Add-WorkerLog ('Deployed {0} file(s) to {1}:{2}' -f $FilesToCopy.Count, $PrimaryFqdn, $Config.RemoteCertDir) 'OK   '
        }

        # --- Import PFX + bind IIS ---
        if ($Config.BindIis)
        {
            $PfxSecure   = ConvertTo-SecureString -String $PfxPlain -AsPlainText -Force
            $RemotePfx   = Join-Path -Path $Config.RemoteCertDir -ChildPath ('{0}.pfx' -f $ShortName)

            $IisResult = Invoke-Command -Session $Session -ScriptBlock {
                param($PfxPath, $PfxSecure, $SiteName, $Port)

                $Status = [PSCustomObject]@{
                    Imported   = $false
                    Bound      = $false
                    Thumbprint = $null
                    Error      = $null
                }

                try
                {
                    $ImportParams = @{
                        FilePath          = $PfxPath
                        CertStoreLocation = 'Cert:\LocalMachine\My'
                        Password          = $PfxSecure
                        Exportable        = $true
                        ErrorAction       = 'Stop'
                    }
                    $Cert = Import-PfxCertificate @ImportParams
                    $Status.Imported   = $true
                    $Status.Thumbprint = $Cert.Thumbprint

                    Import-Module WebAdministration -ErrorAction Stop

                    $Binding = Get-WebBinding -Name $SiteName -Protocol 'https' -Port $Port -ErrorAction SilentlyContinue
                    if (-not $Binding)
                    {
                        New-WebBinding -Name $SiteName -IPAddress '*' -Port $Port -Protocol 'https' -ErrorAction Stop
                    }

                    $SslPath = "IIS:\SslBindings\0.0.0.0!$Port"
                    if (Test-Path $SslPath)
                    {
                        Remove-Item $SslPath -Force
                    }
                    $CertObj = Get-Item ("Cert:\LocalMachine\My\{0}" -f $Cert.Thumbprint)
                    New-Item $SslPath -Value $CertObj -Force -ErrorAction Stop | Out-Null
                    $Status.Bound = $true
                }
                catch
                {
                    $Status.Error = $_.Exception.Message
                }

                return $Status
            } -ArgumentList $RemotePfx, $PfxSecure, $Config.IISSiteName, $Config.IISBindPort

            if ($IisResult.Imported -and $IisResult.Bound)
            {
                $Result.Thumbprint    = $IisResult.Thumbprint
                $Result.IisBindStatus = ('Bound (Thumbprint: {0})' -f $IisResult.Thumbprint)
                Add-WorkerLog ('PFX imported, thumbprint {0}' -f $IisResult.Thumbprint) 'OK   '
                Add-WorkerLog ('IIS bound: {0}:{1}' -f $Config.IISSiteName, $Config.IISBindPort) 'OK   '
            }
            elseif ($IisResult.Imported)
            {
                $Result.Thumbprint    = $IisResult.Thumbprint
                $Result.IisBindStatus = ('Import OK, bind failed: {0}' -f $IisResult.Error)
                Add-WorkerLog ('IIS bind failed: {0}' -f $IisResult.Error) 'WARN '
            }
            else
            {
                $Result.IisBindStatus = ('Import failed: {0}' -f $IisResult.Error)
                Add-WorkerLog ('PFX import failed: {0}' -f $IisResult.Error) 'WARN '
            }
        }

        # --- Verify deployment ---
        if ($Config.VerifyDeployment)
        {
            $ExpectedFiles = @($KeyFile, $PemFile, $CerFile, $PfxFile) |
                Where-Object { Test-Path -LiteralPath $_ } |
                ForEach-Object {
                    [PSCustomObject]@{
                        Name = Split-Path -Path $_ -Leaf
                        Size = (Get-Item -LiteralPath $_).Length
                    }
                }

            $VerifyResult = Invoke-Command -Session $Session -ScriptBlock {
                param($Dir, $Expected, $Thumbprint, $Port)

                $Missing  = [System.Collections.Generic.List[string]]::new()
                $SizeBad  = [System.Collections.Generic.List[string]]::new()

                foreach ($File in $Expected)
                {
                    $Path = Join-Path -Path $Dir -ChildPath $File.Name
                    if (-not (Test-Path -LiteralPath $Path))
                    {
                        $Missing.Add($File.Name)
                    }
                    elseif ((Get-Item -LiteralPath $Path).Length -ne $File.Size)
                    {
                        $SizeBad.Add($File.Name)
                    }
                }

                $BindingOk = $false
                if ($Thumbprint)
                {
                    $SslPath = "IIS:\SslBindings\0.0.0.0!$Port"
                    if (Test-Path $SslPath)
                    {
                        $BoundThumb = (Get-Item $SslPath).Thumbprint
                        $BindingOk  = ($BoundThumb -eq $Thumbprint)
                    }
                }

                return [PSCustomObject]@{
                    Missing   = $Missing
                    SizeBad   = $SizeBad
                    BindingOk = $BindingOk
                }
            } -ArgumentList $Config.RemoteCertDir, $ExpectedFiles, $Result.Thumbprint, $Config.IISBindPort

            $VerifyNotes = [System.Collections.Generic.List[string]]::new()
            if ($VerifyResult.Missing.Count -gt 0)
            {
                $VerifyNotes.Add(('missing: {0}' -f ($VerifyResult.Missing -join ', ')))
            }
            if ($VerifyResult.SizeBad.Count -gt 0)
            {
                $VerifyNotes.Add(('size mismatch: {0}' -f ($VerifyResult.SizeBad -join ', ')))
            }
            if ($Config.BindIis -and -not $VerifyResult.BindingOk)
            {
                $VerifyNotes.Add('IIS binding thumbprint mismatch')
            }

            if ($VerifyNotes.Count -eq 0)
            {
                $Result.VerifyStatus = 'Verified'
                Add-WorkerLog 'Verification passed (files present, sizes match, binding confirmed).' 'OK   '
            }
            else
            {
                $Result.VerifyStatus = ('Issues: {0}' -f ($VerifyNotes -join '; '))
                Add-WorkerLog ('Verification issues: {0}' -f ($VerifyNotes -join '; ')) 'WARN '
            }
        }
    }
    catch
    {
        Add-WorkerLog ('Remote stage error on {0}: {1}' -f $PrimaryFqdn, $_.Exception.Message) 'ERROR'
    }
    finally
    {
        if ($Session)
        {
            Remove-PSSession -Session $Session -ErrorAction SilentlyContinue
        }
    }

    return $Result
}

# ============================================================
# REGION: SCAN MUSIC (MENU OPTION 6)
# ============================================================

function Initialize-ScanMusicInterop
{
    if ('CerteratorMidi.Native' -as [type])
    {
        return
    }

    $TypeDefinition = @'
using System;
using System.Runtime.InteropServices;
using System.Text;

namespace CerteratorMidi
{
    public static class Native
    {
        [DllImport("winmm.dll", CharSet = CharSet.Auto)]
        public static extern int mciSendString(string command, StringBuilder returnValue, int returnLength, IntPtr callback);
    }
}
'@

    Add-Type -TypeDefinition $TypeDefinition -Language CSharp
}

function Get-ScanMusicPath
{
    $Root = $PSScriptRoot

    if ([string]::IsNullOrWhiteSpace($Root))
    {
        $Root = (Get-Location).Path
    }

    return (Join-Path -Path $Root -ChildPath $script:ScanMusicRelativePath)
}

function Get-ScanMusicLooper
{
    # Returned scriptblock runs on a dedicated background runspace so the
    # parallel scan on the main thread is never blocked. It opens the MIDI as an
    # MCI sequencer and then plays it with a BLOCKING "wait" on each pass -- the
    # same call IpanemaMID.ps1 uses, which is what actually drives audible
    # sequencer output (an asynchronous "play" without a message pump stays
    # silent). After each pass it rewinds and replays, giving a clean loop,
    # until either the shared synchronized $Control.Stop flag is set or the
    # $Control.MaxPlays cap of completed passes is reached (a cap of 0 or less
    # loops until stopped). Stop-ScanMusic sets that flag and sends an MCI
    # "stop" from the main thread, which interrupts the blocking play so the
    # loop exits promptly. The interop type is loaded process-wide by
    # Initialize-ScanMusicInterop before this runs.
    return {
        param
        (
            [string]$MidiPath,
            [string]$Alias,
            [hashtable]$Control
        )

        $OpenCommand = 'open "{0}" type sequencer alias {1}' -f $MidiPath, $Alias
        $OpenResult  = [CerteratorMidi.Native]::mciSendString($OpenCommand, $null, 0, [IntPtr]::Zero)

        # Report startup success back to the main thread so it can fall back to
        # another method if the device could not be opened.
        $Control.Started = ($OpenResult -eq 0)

        if ($OpenResult -ne 0)
        {
            return
        }

        try
        {
            $Failures = 0
            $Plays    = 0
            $MaxPlays = [int]$Control.MaxPlays

            # A $MaxPlays of 0 or less loops until the stop flag is set; any
            # positive value caps the number of completed passes.
            while (-not $Control.Stop -and $Failures -lt 5 -and ($MaxPlays -le 0 -or $Plays -lt $MaxPlays))
            {
                [void][CerteratorMidi.Native]::mciSendString(('seek {0} to start' -f $Alias), $null, 0, [IntPtr]::Zero)
                $PlayResult = [CerteratorMidi.Native]::mciSendString(('play {0} wait' -f $Alias), $null, 0, [IntPtr]::Zero)

                if ($PlayResult -eq 0)
                {
                    # A clean, uninterrupted pass played to its end; count it
                    # toward the cap.
                    $Plays++
                }
                elseif (-not $Control.Stop)
                {
                    # A non-zero result with the flag still clear indicates a
                    # real device fault. (A stop-interrupted play also returns
                    # non-zero, but then $Control.Stop is already set and the
                    # loop exits without counting it.) Guard against a hot spin.
                    $Failures++
                    Start-Sleep -Milliseconds 250
                }
            }
        }
        finally
        {
            [void][CerteratorMidi.Native]::mciSendString(('stop {0}' -f $Alias), $null, 0, [IntPtr]::Zero)
            [void][CerteratorMidi.Native]::mciSendString(('close {0}' -f $Alias), $null, 0, [IntPtr]::Zero)
        }
    }
}

function Start-ScanMusicViaMci
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$MidiPath
    )

    Initialize-ScanMusicInterop

    $Control = [hashtable]::Synchronized(@{ Stop = $false; MaxPlays = $script:ScanMusicMaxPlays })
    $Looper  = Get-ScanMusicLooper

    $Shell = [powershell]::Create()
    [void]$Shell.AddScript($Looper.ToString())
    [void]$Shell.AddArgument($MidiPath)
    [void]$Shell.AddArgument($script:ScanMusicMciAlias)
    [void]$Shell.AddArgument($Control)

    $Handle = $Shell.BeginInvoke()

    # Wait briefly for the worker to report whether the MCI device opened, so a
    # failure can fall back to Windows Media Player rather than playing nothing.
    $Deadline = (Get-Date).AddSeconds(2)
    while (-not $Control.ContainsKey('Started') -and (Get-Date) -lt $Deadline)
    {
        Start-Sleep -Milliseconds 50
    }

    if ($Control.ContainsKey('Started') -and -not $Control.Started)
    {
        $Control.Stop = $true

        try
        {
            [void]$Shell.EndInvoke($Handle)
        }
        catch
        {
        }

        $Shell.Dispose()
        return $null
    }

    return [PSCustomObject]@{
        Method   = 'MCI'
        Shell    = $Shell
        Handle   = $Handle
        Control  = $Control
        Alias    = $script:ScanMusicMciAlias
        Player   = $null
        Runspace = $null
    }
}

function Get-ScanMusicWmpLooper
{
    # Returned scriptblock runs on a dedicated STA runspace (WMPlayer.OCX is an
    # ActiveX control and must be created and used on an STA thread). The COM
    # object is created, played, and released entirely on that thread and is
    # never marshalled back to the main thread. Native looping is disabled so
    # each pass can be counted: the block plays the file, polls playState until
    # the pass ends, counts it, and repeats until the shared synchronized
    # $Control.Stop flag is set or the $Control.MaxPlays cap is reached (a cap
    # of 0 or less loops until stopped). Stop-ScanMusic sets the flag, and the
    # frequent stop-flag checks let an early scan completion silence playback
    # promptly. Open success is reported via $Control.Started.
    return {
        param
        (
            [string]$MidiPath,
            [hashtable]$Control
        )

        $WmpStopped    = 1
        $WmpPlaying    = 3
        $WmpMediaEnded = 8
        $Player        = $null

        try
        {
            $Player = New-Object -ComObject 'WMPlayer.OCX'
            $Player.settings.volume = 100
            [void]$Player.settings.setMode('loop', $false)
            $Player.URL = $MidiPath

            $Control.Started = $true

            $Plays    = 0
            $MaxPlays = [int]$Control.MaxPlays

            while (-not $Control.Stop -and ($MaxPlays -le 0 -or $Plays -lt $MaxPlays))
            {
                $Player.controls.currentPosition = 0
                $Player.controls.play()

                # Wait for this pass to actually begin so a slow start is not
                # mistaken for an ended pass.
                $StartDeadline = (Get-Date).AddSeconds(5)
                while (-not $Control.Stop -and $Player.playState -ne $WmpPlaying -and (Get-Date) -lt $StartDeadline)
                {
                    Start-Sleep -Milliseconds 50
                }

                # Play until the pass ends (or the player stops), re-checking
                # the stop flag frequently.
                while (-not $Control.Stop -and $Player.playState -ne $WmpStopped -and $Player.playState -ne $WmpMediaEnded)
                {
                    Start-Sleep -Milliseconds 100
                }

                if (-not $Control.Stop)
                {
                    $Plays++
                }
            }
        }
        finally
        {
            if ($null -ne $Player)
            {
                try
                {
                    $Player.controls.stop()
                }
                catch
                {
                }

                try
                {
                    [void][System.Runtime.InteropServices.Marshal]::FinalReleaseComObject($Player)
                }
                catch
                {
                }
            }

            [System.GC]::Collect()
            [System.GC]::WaitForPendingFinalizers()
        }
    }
}

function Start-ScanMusicViaWmp
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$MidiPath
    )

    $Control = [hashtable]::Synchronized(@{ Stop = $false; MaxPlays = $script:ScanMusicMaxPlays })
    $Looper  = Get-ScanMusicWmpLooper

    # WMPlayer.OCX is an ActiveX control and must run on an STA thread; a
    # default background runspace is MTA, so create an explicit STA runspace.
    $Runspace = [runspacefactory]::CreateRunspace()
    $Runspace.ApartmentState = 'STA'
    $Runspace.ThreadOptions  = 'ReuseThread'
    $Runspace.Open()

    $Shell = [powershell]::Create()
    $Shell.Runspace = $Runspace
    [void]$Shell.AddScript($Looper.ToString())
    [void]$Shell.AddArgument($MidiPath)
    [void]$Shell.AddArgument($Control)

    $Handle = $Shell.BeginInvoke()

    # Wait briefly for the worker to report that the player initialised so a
    # failure surfaces here rather than playing nothing silently.
    $Deadline = (Get-Date).AddSeconds(2)
    while (-not $Control.ContainsKey('Started') -and (Get-Date) -lt $Deadline)
    {
        Start-Sleep -Milliseconds 50
    }

    # If the player could not be created on the worker, tear the runspace down
    # and report failure so the caller continues without scan music.
    if (-not $Control.ContainsKey('Started') -or -not $Control.Started)
    {
        $Control.Stop = $true

        try
        {
            [void]$Shell.EndInvoke($Handle)
        }
        catch
        {
        }

        $Shell.Dispose()

        try
        {
            $Runspace.Close()
            $Runspace.Dispose()
        }
        catch
        {
        }

        return $null
    }

    return [PSCustomObject]@{
        Method   = 'WMP'
        Shell    = $Shell
        Handle   = $Handle
        Control  = $Control
        Alias    = $null
        Player   = $null
        Runspace = $Runspace
    }
}

function Start-ScanMusic
{
    if (-not $script:EnableScanMusic)
    {
        return $null
    }

    $MidiPath = Get-ScanMusicPath

    if (-not (Test-Path -LiteralPath $MidiPath))
    {
        Write-WarnMsg ('Scan music file not found; continuing without it: {0}' -f $MidiPath)
        return $null
    }

    $PlayNote = if ($script:ScanMusicMaxPlays -gt 0)
    {
        'playing up to {0} time(s) or until the scan completes' -f $script:ScanMusicMaxPlays
    }
    else
    {
        'looping until the scan completes'
    }

    # Prefer MCI (winmm): no external dependency, and it is the method
    # IpanemaMID.ps1 confirms works on this host. Fall back to Windows Media
    # Player if the MCI sequencer device cannot be opened.
    try
    {
        $Music = Start-ScanMusicViaMci -MidiPath $MidiPath

        if ($null -ne $Music)
        {
            Write-InfoMsg ('Scan music started (MCI); {0}.' -f $PlayNote)
            return $Music
        }

        Write-WarnMsg 'MCI playback was unavailable; trying Windows Media Player.'
    }
    catch
    {
        Write-WarnMsg ('MCI playback failed; trying Windows Media Player: {0}' -f $_.Exception.Message)
    }

    try
    {
        $Music = Start-ScanMusicViaWmp -MidiPath $MidiPath

        if ($null -ne $Music)
        {
            Write-InfoMsg ('Scan music started (Windows Media Player); {0}.' -f $PlayNote)
            return $Music
        }

        Write-WarnMsg 'Windows Media Player playback was unavailable; continuing without scan music.'
        return $null
    }
    catch
    {
        Write-WarnMsg ('No MIDI playback method was available; continuing without scan music: {0}' -f $_.Exception.Message)
        return $null
    }
}

function Stop-ScanMusic
{
    param
    (
        [PSObject]$Music
    )

    if ($null -eq $Music)
    {
        return
    }

    try
    {
        switch ($Music.Method)
        {
            'MCI'
            {
                $Music.Control.Stop = $true

                # Interrupt the worker's blocking play from the main thread.
                try
                {
                    [void][CerteratorMidi.Native]::mciSendString(('stop {0}' -f $Music.Alias), $null, 0, [IntPtr]::Zero)
                }
                catch
                {
                }

                try
                {
                    [void]$Music.Shell.EndInvoke($Music.Handle)
                }
                catch
                {
                }

                $Music.Shell.Dispose()
            }

            'WMP'
            {
                if ($null -ne $Music.Control)
                {
                    $Music.Control.Stop = $true
                }

                # The Windows Media Player COM object lives entirely on the
                # worker's STA runspace; setting the stop flag lets that worker
                # stop the player and release the object on the same thread that
                # created it. Wait for it to finish, then tear the runspace down.
                try
                {
                    [void]$Music.Shell.EndInvoke($Music.Handle)
                }
                catch
                {
                }

                $Music.Shell.Dispose()

                if ($null -ne $Music.Runspace)
                {
                    try
                    {
                        $Music.Runspace.Close()
                        $Music.Runspace.Dispose()
                    }
                    catch
                    {
                    }
                }
            }
        }

        Write-InfoMsg 'Scan music stopped.'
    }
    catch
    {
        Write-WarnMsg ('Scan music did not stop cleanly: {0}' -f $_.Exception.Message)
    }
}

# ============================================================
# REGION: CERTIFICATE SCAN (WORKER)
# ============================================================

# Self-contained per-server certificate-expiry probe. Like $ServerWorker it
# also runs inside isolated RunspacePool threads, so it never calls the
# script-scope logging helpers or touches the shared log file. It buffers
# structured log entries and returns them with the per-server match list; the
# main thread replays them through the standard Write-*Msg helpers.
$CertScanWorker = {
    param
    (
        [PSCustomObject]$WorkItem,
        [hashtable]$Config,
        [System.Management.Automation.PSCredential]$SACred
    )

    $LogEntries = [System.Collections.Generic.List[object]]::new()

    function Add-WorkerLog
    {
        param
        (
            [string]$Message,
            [string]$Tag = 'INFO '
        )

        $LogEntries.Add([PSCustomObject]@{ Tag = $Tag; Message = $Message })
    }

    $ShortName = $WorkItem.ShortName
    $Fqdn      = $WorkItem.Fqdn
    $MatchList = [System.Collections.Generic.List[PSCustomObject]]::new()

    $Result = [PSCustomObject]@{
        Server     = $ShortName
        Fqdn       = $Fqdn
        Reachable  = 'No'
        MatchCount = 0
        Matches    = $MatchList
        LogEntries = $LogEntries
    }

    Add-WorkerLog ('Scanning {0} for certificates expiring on {1}' -f $Fqdn, $Config.TargetDate)

    if ($Config.DryRun)
    {
        Add-WorkerLog ('Would open a PSSession to {0} and inspect {1}.' -f $Fqdn, $Config.StorePath) 'DRYRUN'
        $Result.Reachable = 'DryRun'
        return $Result
    }

    $Reachable = $false
    try
    {
        $Reachable = [bool](Test-WSMan -ComputerName $Fqdn -ErrorAction SilentlyContinue)
    }
    catch
    {
        $Reachable = $false
    }

    if (-not $Reachable)
    {
        Add-WorkerLog ('{0} is not reachable over WinRM; skipping.' -f $Fqdn) 'WARN '
        return $Result
    }

    $Session = $null
    try
    {
        if ($Config.UseCurrentIdentity)
        {
            $Session = New-PSSession -ComputerName $Fqdn -ErrorAction Stop
        }
        else
        {
            $Session = New-PSSession -ComputerName $Fqdn -Credential $SACred -ErrorAction Stop
        }

        $Result.Reachable = 'Yes'
        Add-WorkerLog ('PSSession opened: {0}' -f $Fqdn) 'OK   '
    }
    catch
    {
        Add-WorkerLog ('Failed to open PSSession to {0}: {1}' -f $Fqdn, $_.Exception.Message) 'ERROR'
        $Result.Reachable = 'Session failed'
        return $Result
    }

    try
    {
        $RemoteScan = {
            param
            (
                [string]$StorePath,
                [string]$TargetDateString,
                [string]$OidTemplateInfo,
                [string]$OidTemplateNameV1,
                [string]$OidSubjectAltName
            )

            $Target = ([datetime]$TargetDateString).Date
            $Found  = [System.Collections.Generic.List[PSCustomObject]]::new()

            $Certs = Get-ChildItem -Path $StorePath -ErrorAction SilentlyContinue
            foreach ($Cert in $Certs)
            {
                if ($Cert.NotAfter.Date -ne $Target)
                {
                    continue
                }

                $TemplateName = 'Not present'
                foreach ($Oid in @($OidTemplateInfo, $OidTemplateNameV1))
                {
                    $Ext = $Cert.Extensions |
                        Where-Object { $_.Oid.Value -eq $Oid } |
                        Select-Object -First 1

                    if ($Ext)
                    {
                        $Formatted = ($Ext.Format($true) -split '\r?\n' |
                            ForEach-Object { $_.Trim() } |
                            Where-Object { $_ -ne '' }) -join '; '

                        $NameMatch = [regex]::Match($Formatted, 'Template=([^(;\r\n]+)')
                        if ($NameMatch.Success)
                        {
                            $TemplateName = $NameMatch.Groups[1].Value.Trim()
                        }
                        else
                        {
                            $TemplateName = $Formatted
                        }

                        break
                    }
                }

                $DnsNames    = [System.Collections.Generic.List[string]]::new()
                $IpAddresses = [System.Collections.Generic.List[string]]::new()

                $San = $Cert.Extensions |
                    Where-Object { $_.Oid.Value -eq $OidSubjectAltName } |
                    Select-Object -First 1

                if ($San)
                {
                    $SanText = $San.Format($true)

                    foreach ($DnsHit in [regex]::Matches($SanText, 'DNS Name=([^,\r\n]+)'))
                    {
                        $Value = $DnsHit.Groups[1].Value.Trim()
                        if ($Value -ne '' -and -not $DnsNames.Contains($Value))
                        {
                            $DnsNames.Add($Value)
                        }
                    }

                    foreach ($IpHit in [regex]::Matches($SanText, 'IP Address=([^,\r\n]+)'))
                    {
                        $Value = $IpHit.Groups[1].Value.Trim()
                        if ($Value -ne '' -and -not $IpAddresses.Contains($Value))
                        {
                            $IpAddresses.Add($Value)
                        }
                    }
                }

                $CommonName = ''
                $CnMatch    = [regex]::Match($Cert.Subject, 'CN=([^,]+)')
                if ($CnMatch.Success)
                {
                    $CommonName = $CnMatch.Groups[1].Value.Trim()
                }

                $Found.Add([PSCustomObject]@{
                    Subject    = $Cert.Subject
                    CommonName = $CommonName
                    NotAfter   = $Cert.NotAfter
                    Thumbprint = $Cert.Thumbprint
                    Template   = $TemplateName
                    DnsSans    = @($DnsNames)
                    IpSans     = @($IpAddresses)
                    Store      = $StorePath
                })
            }

            return $Found
        }

        $ScanArgs = @(
            $Config.StorePath
            $Config.TargetDate
            $Config.OidTemplateInfo
            $Config.OidTemplateNameV1
            $Config.OidSubjectAltName
        )

        $Remote = Invoke-Command -Session $Session -ScriptBlock $RemoteScan -ArgumentList $ScanArgs

        foreach ($Hit in $Remote)
        {
            $MatchList.Add([PSCustomObject]@{
                Server      = $ShortName
                Fqdn        = $Fqdn
                CommonName  = $Hit.CommonName
                Template    = $Hit.Template
                DnsSans     = @($Hit.DnsSans)
                IpSans      = @($Hit.IpSans)
                DnsSansText = (@($Hit.DnsSans) -join ', ')
                IpSansText  = (@($Hit.IpSans) -join ', ')
                NotAfter    = $Hit.NotAfter
                Thumbprint  = $Hit.Thumbprint
                Store       = $Hit.Store
            })
        }

        $Result.MatchCount = $MatchList.Count

        if ($MatchList.Count -gt 0)
        {
            Add-WorkerLog ('{0}: {1} certificate(s) expire on {2}.' -f $Fqdn, $MatchList.Count, $Config.TargetDate) 'OK   '
        }
        else
        {
            Add-WorkerLog ('{0}: no certificates expire on {1}.' -f $Fqdn, $Config.TargetDate)
        }
    }
    catch
    {
        Add-WorkerLog ('Certificate scan failed on {0}: {1}' -f $Fqdn, $_.Exception.Message) 'ERROR'
    }
    finally
    {
        if ($Session)
        {
            Remove-PSSession -Session $Session -ErrorAction SilentlyContinue
        }
    }

    return $Result
}

# ============================================================
# REGION: ORCHESTRATION FUNCTIONS
# ============================================================

function Get-WorkerConfig
{
    return @{
        OpenSSLPath      = $script:OpenSSLPath
        KeyLength        = $script:KeyLength
        CAConfig         = $script:CAConfig
        OutputRoot       = $script:OutputRoot
        RemoteCertDir    = $script:RemoteCertDir
        IISSiteName      = $script:IISSiteName
        IISBindPort      = $script:IISBindPort
        CAChainFile      = $script:CAChainFile
        PrimaryDomain    = $script:PrimaryDomain
        AlternateDomain  = $script:AlternateDomain
        Country          = $script:Country
        State            = $script:State
        Locality         = $script:Locality
        Organization     = $script:Organization
        OrgUnit          = $script:OrgUnit
        DryRun           = $script:DryRun
        ExportPfx        = $script:ExportPfx
        DeployToRemote   = $script:DeployToRemote
        BindIis          = $script:BindIis
        VerifyDeployment   = $script:VerifyDeployment
        UseCurrentIdentity = $script:UseCurrentIdentity
    }
}

function Invoke-Pipeline
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$WorkItems
    )

    $WorkerConfig = Get-WorkerConfig
    $Results      = [System.Collections.Generic.List[PSCustomObject]]::new()

    if ($script:UseParallel -and $WorkItems.Count -gt 1 -and -not $script:DryRun)
    {
        Write-InfoMsg ('Processing {0} server(s) across up to {1} parallel runspaces.' -f $WorkItems.Count, $script:MaxConcurrency)

        $Pool = [runspacefactory]::CreateRunspacePool(1, $script:MaxConcurrency)
        $Pool.Open()

        $Jobs = [System.Collections.Generic.List[PSCustomObject]]::new()

        foreach ($Item in $WorkItems)
        {
            $PS = [powershell]::Create()
            $PS.RunspacePool = $Pool
            [void]$PS.AddScript($script:ServerWorker.ToString())
            [void]$PS.AddArgument($Item)
            [void]$PS.AddArgument($WorkerConfig)
            [void]$PS.AddArgument($script:SACred)
            [void]$PS.AddArgument($script:PfxPlain)

            $Jobs.Add([PSCustomObject]@{
                Server = $Item.ShortName
                PS     = $PS
                Handle = $PS.BeginInvoke()
            })
        }

        foreach ($Job in $Jobs)
        {
            try
            {
                $Output = $Job.PS.EndInvoke($Job.Handle)
                foreach ($Item in $Output)
                {
                    if ($Item -is [PSCustomObject] -and $Item.PSObject.Properties.Name -contains 'LogEntries')
                    {
                        $Results.Add($Item)
                    }
                }
            }
            catch
            {
                Write-ErrorMsg ('Runspace for {0} failed: {1}' -f $Job.Server, $_.Exception.Message)
            }
            finally
            {
                $Job.PS.Dispose()
            }
        }

        $Pool.Close()
        $Pool.Dispose()
    }
    else
    {
        if ($script:UseParallel -and $script:DryRun)
        {
            Write-DryRunMsg 'Parallelism is bypassed under DryRun; processing sequentially.'
        }

        foreach ($Item in $WorkItems)
        {
            $Output = & $script:ServerWorker $Item $WorkerConfig $script:SACred $script:PfxPlain
            foreach ($Single in $Output)
            {
                if ($Single -is [PSCustomObject] -and $Single.PSObject.Properties.Name -contains 'LogEntries')
                {
                    $Results.Add($Single)
                }
            }
        }
    }

    return $Results
}

function Show-ResultLogs
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$Results
    )

    foreach ($Item in $Results)
    {
        Write-Host ''
        Write-Host ('----- {0} ({1}) -----' -f $Item.Server, $Item.CommonName) -ForegroundColor Cyan
        Write-Log -Message ('----- {0} ({1}) -----' -f $Item.Server, $Item.CommonName) -Tag 'INFO '

        foreach ($Entry in $Item.LogEntries)
        {
            Write-BufferedEntry -Tag $Entry.Tag -Message $Entry.Message
        }
    }
}

function Get-ScanWorkerConfig
{
    return @{
        PrimaryDomain      = $script:PrimaryDomain
        AlternateDomain    = $script:AlternateDomain
        StorePath          = $script:CertScanStorePath
        TargetDate         = $script:CertScanResolvedDate
        DryRun             = $script:DryRun
        UseCurrentIdentity = $script:UseCurrentIdentity
        OidTemplateInfo    = $script:OidTemplateInfo
        OidTemplateNameV1  = $script:OidTemplateNameV1
        OidSubjectAltName  = $script:OidSubjectAltName
    }
}

function Update-ScanProgress
{
    param
    (
        [Parameter(Mandatory = $true)]
        [int]$Completed,

        [Parameter(Mandatory = $true)]
        [int]$Total,

        [switch]$Finished
    )

    $Activity = 'Scanning servers for expiring certificates'

    if ($Finished)
    {
        Write-Progress -Activity $Activity -Completed
        return
    }

    if ($Total -le 0)
    {
        return
    }

    $Percent = [int][math]::Floor(($Completed / $Total) * 100)
    if ($Percent -lt 0)
    {
        $Percent = 0
    }
    if ($Percent -gt 100)
    {
        $Percent = 100
    }

    $StatusText = '{0} of {1} server(s) scanned ({2}%)' -f $Completed, $Total, $Percent

    $ProgressSplat = @{
        Activity        = $Activity
        Status          = $StatusText
        PercentComplete = $Percent
    }
    Write-Progress @ProgressSplat
}

function Start-CertScan
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$WorkItems
    )

    $WorkerConfig = Get-ScanWorkerConfig
    $Results      = [System.Collections.Generic.List[PSCustomObject]]::new()

    if ($script:UseParallel -and $WorkItems.Count -gt 1 -and -not $script:DryRun)
    {
        Write-InfoMsg ('Scanning {0} server(s) across up to {1} parallel runspaces.' -f $WorkItems.Count, $script:MaxConcurrency)

        $Pool = [runspacefactory]::CreateRunspacePool(1, $script:MaxConcurrency)
        $Pool.Open()

        $Jobs = [System.Collections.Generic.List[PSCustomObject]]::new()

        foreach ($Item in $WorkItems)
        {
            $PS = [powershell]::Create()
            $PS.RunspacePool = $Pool
            [void]$PS.AddScript($script:CertScanWorker.ToString())
            [void]$PS.AddArgument($Item)
            [void]$PS.AddArgument($WorkerConfig)
            [void]$PS.AddArgument($script:SACred)

            $Jobs.Add([PSCustomObject]@{
                Server = $Item.ShortName
                PS     = $PS
                Handle = $PS.BeginInvoke()
            })
        }

        $Total     = $Jobs.Count
        $Completed = 0
        Update-ScanProgress -Completed 0 -Total $Total

        while ($Completed -lt $Total)
        {
            Start-Sleep -Milliseconds 250
            $Completed = @($Jobs | Where-Object { $_.Handle.IsCompleted }).Count
            Update-ScanProgress -Completed $Completed -Total $Total
        }

        foreach ($Job in $Jobs)
        {
            try
            {
                $Output = $Job.PS.EndInvoke($Job.Handle)
                foreach ($Item in $Output)
                {
                    if ($Item -is [PSCustomObject] -and $Item.PSObject.Properties.Name -contains 'LogEntries')
                    {
                        $Results.Add($Item)
                    }
                }
            }
            catch
            {
                Write-ErrorMsg ('Scan runspace for {0} failed: {1}' -f $Job.Server, $_.Exception.Message)
            }
            finally
            {
                $Job.PS.Dispose()
            }
        }

        Update-ScanProgress -Completed $Total -Total $Total -Finished

        $Pool.Close()
        $Pool.Dispose()
    }
    else
    {
        if ($script:UseParallel -and $script:DryRun)
        {
            Write-DryRunMsg 'Parallelism is bypassed under DryRun; scanning sequentially.'
        }

        $Total = $WorkItems.Count
        $Index = 0
        Update-ScanProgress -Completed 0 -Total $Total

        foreach ($Item in $WorkItems)
        {
            $Output = & $script:CertScanWorker $Item $WorkerConfig $script:SACred
            foreach ($Single in $Output)
            {
                if ($Single -is [PSCustomObject] -and $Single.PSObject.Properties.Name -contains 'LogEntries')
                {
                    $Results.Add($Single)
                }
            }

            $Index++
            Update-ScanProgress -Completed $Index -Total $Total
        }

        Update-ScanProgress -Completed $Total -Total $Total -Finished
    }

    return $Results
}

function Show-ScanLogs
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$Results
    )

    # Per-server scan detail is written to the log file only; the console shows
    # the progress bar during the scan and the summary block afterward.
    foreach ($Item in $Results)
    {
        Write-Log -Message ('----- {0} -----' -f $Item.Fqdn) -Tag 'INFO '

        foreach ($Entry in $Item.LogEntries)
        {
            Write-Log -Message $Entry.Message -Tag $Entry.Tag
        }
    }
}

# ============================================================
# REGION: REPORTING FUNCTIONS
# ============================================================

function Build-HtmlReport
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$Results,

        [Parameter(Mandatory = $true)]
        [string]$RunMode
    )

    $Rows = [System.Collections.Generic.List[string]]::new()

    foreach ($Item in $Results)
    {
        $CsrColor = if ($Item.CsrStatus -eq 'Success' -or $Item.CsrStatus -eq 'DryRun') { '#1a7f37' } else { '#b42318' }

        switch -Wildcard ($Item.SubmitStatus)
        {
            'Issued'   { $SubColor = '#1a7f37' }
            'DryRun'   { $SubColor = '#8a2be2' }
            'Pending*' { $SubColor = '#8a6d00' }
            'Skipped'  { $SubColor = '#8a6d00' }
            default    { $SubColor = '#b42318' }
        }

        $Row = @"
<tr>
  <td>$($Item.Server)</td>
  <td>$($Item.CommonName)</td>
  <td>$($Item.Template)</td>
  <td>$($Item.DnsSans)</td>
  <td>$($Item.IpSans)</td>
  <td style="color:$CsrColor;font-weight:bold;">$($Item.CsrStatus)</td>
  <td style="color:$SubColor;font-weight:bold;">$($Item.SubmitStatus)</td>
  <td>$($Item.RequestId)</td>
  <td>$($Item.ChainStatus)</td>
  <td>$($Item.PfxStatus)</td>
  <td>$($Item.RemoteDirStatus)</td>
  <td>$($Item.DeployStatus)</td>
  <td>$($Item.IisBindStatus)</td>
  <td>$($Item.VerifyStatus)</td>
  <td>$($Item.Thumbprint)</td>
</tr>
"@
        $Rows.Add($Row)
    }

    $RowsHtml = $Rows -join [Environment]::NewLine
    $DryNote  = if ($script:DryRun) { '<p style="color:#8a2be2;font-weight:bold;">DRYRUN MODE - no files were written, nothing was submitted, and no remote operations ran.</p>' } else { '' }

    $Html = @"
