<head>
<style>
    body  { font-family: Segoe UI, Arial, sans-serif; font-size: 12px; color: #1f2328; }
    h2    { color: #0b3d91; margin-bottom: 2px; }
    .meta { color: #57606a; font-size: 12px; margin-top: 0; }
    table { border-collapse: collapse; width: 100%; margin-top: 12px; }
    th    { background: #0b3d91; color: #ffffff; text-align: left; padding: 6px 8px; font-size: 11px; }
    td    { border: 1px solid #d0d7de; padding: 5px 8px; vertical-align: top; }
    tr:nth-child(even) td { background: #f6f8fa; }
</style>
</head>
<body>
    <h2>$($script:ReportTitle)</h2>
    <p class="meta">Run mode: $RunMode &nbsp;|&nbsp; Generated: $($script:FriendlyDate) &nbsp;|&nbsp; CA: $($script:CAConfig) &nbsp;|&nbsp; Parallel: $($script:UseParallel)</p>
    $DryNote
    <table>
        <tr>
            <th>Server</th>
            <th>Common Name</th>
            <th>Template</th>
            <th>DNS SANs</th>
            <th>IP SANs</th>
            <th>CSR</th>
            <th>Submission</th>
            <th>Request ID</th>
            <th>Chain</th>
            <th>PFX</th>
            <th>Remote Dir</th>
            <th>Deploy</th>
            <th>IIS Bind</th>
            <th>Verify</th>
            <th>Thumbprint</th>
        </tr>
        $RowsHtml
    </table>
</body>
</html>
"@

    return $Html
}

function New-EmailLogoLinkedResource
{
    if (-not $script:EmailLogoEnabled)
    {
        return $null
    }

    if ([string]::IsNullOrWhiteSpace($script:EmailLogoBase64))
    {
        Write-WarnMsg 'Email logo is enabled but no Base64 image data is configured; sending without the inline logo.'
        return $null
    }

    try
    {
        $Bytes  = [System.Convert]::FromBase64String($script:EmailLogoBase64)
        $Stream = New-Object System.IO.MemoryStream(, $Bytes)

        $ContentType = New-Object System.Net.Mime.ContentType('image/jpeg')
        $Resource    = New-Object System.Net.Mail.LinkedResource($Stream, $ContentType)

        $Resource.ContentId        = $script:EmailLogoContentId
        $Resource.TransferEncoding = [System.Net.Mime.TransferEncoding]::Base64

        return $Resource
    }
    catch
    {
        Write-WarnMsg ('Failed to build the inline email logo resource: {0}' -f $_.Exception.Message)
        return $null
    }
}

function Send-ReportEmail
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$HtmlBody,

        [string[]]$Attachments = @(),

        [string]$Subject = '',

        [switch]$IncludeLogo
    )

    if (-not $script:SendEmail)
    {
        Write-InfoMsg 'Email reporting is disabled ($SendEmail = $false). Skipping send.'
        return
    }

    if ([string]::IsNullOrWhiteSpace($Subject))
    {
        $Subject = Get-EmailSubject
    }

    if ($script:DryRun)
    {
        Write-DryRunMsg ('Would send HTML report "{0}" to: {1}' -f $Subject, ($script:MailTo -join ', '))
        return
    }

    $Message = $null
    $Smtp    = $null

    try
    {
        $Message         = New-Object System.Net.Mail.MailMessage
        $Message.From    = New-Object System.Net.Mail.MailAddress($script:MailFrom)
        $Message.Subject = $Subject
        $Message.SubjectEncoding = [System.Text.Encoding]::UTF8

        foreach ($Recipient in $script:MailTo)
        {
            if (-not [string]::IsNullOrWhiteSpace($Recipient))
            {
                $Message.To.Add($Recipient.Trim())
            }
        }

        $HtmlView = [System.Net.Mail.AlternateView]::CreateAlternateViewFromString($HtmlBody, [System.Text.Encoding]::UTF8, 'text/html')

        if ($IncludeLogo)
        {
#            $LogoResource = New-EmailLogoLinkedResource
            $LogoResource = New-EmailBodyLogoResource
            if ($null -ne $LogoResource)
            {
                $HtmlView.LinkedResources.Add($LogoResource)
            }
        }

        $Message.AlternateViews.Add($HtmlView)

        $ExistingAttachments = @($Attachments | Where-Object { $_ -and (Test-Path -LiteralPath $_) })
        foreach ($AttachmentPath in $ExistingAttachments)
        {
            $Message.Attachments.Add((New-Object System.Net.Mail.Attachment($AttachmentPath)))
        }

        $Smtp = New-Object System.Net.Mail.SmtpClient($script:SmtpServer, $script:SmtpPort)
        $Smtp.Send($Message)

        Write-SuccessMsg ('Report emailed to: {0}' -f ($script:MailTo -join ', '))
    }
    catch
    {
        Write-ErrorMsg ('Failed to send report email: {0}' -f $_.Exception.Message)
    }
    finally
    {
        if ($null -ne $Smtp)
        {
            $Smtp.Dispose()
        }

        if ($null -ne $Message)
        {
            $Message.Dispose()
        }
    }
}

function Complete-Run
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$WorkItems,

        [Parameter(Mandatory = $true)]
        [string]$RunMode
    )

    if ($WorkItems.Count -eq 0)
    {
        Write-WarnMsg 'No servers to process. Returning to the main menu.'
        return
    }

    # Acquire credentials / secrets only when a stage needs them.
    if ((Test-RemoteStageEnabled) -and -not $script:DryRun)
    {
        if (-not (Request-RemoteCredential))
        {
            return
        }
    }

    if ($script:ExportPfx -and -not $script:DryRun)
    {
        if (-not (Request-PfxPassword))
        {
            return
        }
    }

    # WinRM pre-flight for remote stages.
    $ToProcess = $WorkItems
    if ((Test-RemoteStageEnabled) -and -not $script:DryRun)
    {
        $ToProcess = Test-ServerReachable -WorkItems $WorkItems
    }

    $Results = Invoke-Pipeline -WorkItems $ToProcess
    Show-ResultLogs -Results $Results

    $Html = Build-HtmlReport -Results $Results -RunMode $RunMode
    Send-ReportEmail -HtmlBody $Html
}

