function Export-CertScanListing
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$MatchList
    )

    if (-not (Test-Path -LiteralPath $script:CertScanReportRoot))
    {
        $null = New-Item -Path $script:CertScanReportRoot -ItemType Directory -Force
    }

    $FileName = '{0}_ExpiringCerts_{1}.csv' -f $script:ScriptName, $script:RunStamp
    $CsvPath  = Join-Path -Path $script:CertScanReportRoot -ChildPath $FileName

    $Export = foreach ($Item in $MatchList)
    {
        $Expiry = if ($Item.NotAfter -is [datetime]) { $Item.NotAfter.ToString('yyyy-MM-dd') } else { [string]$Item.NotAfter }

        [PSCustomObject]@{
            Server     = $Item.Server
            Fqdn       = $Item.Fqdn
            CommonName = $Item.CommonName
            Template   = $Item.Template
            DnsSans    = $Item.DnsSansText
            IpSans     = $Item.IpSansText
            Expires    = $Expiry
            Thumbprint = $Item.Thumbprint
            Store      = $Item.Store
        }
    }

    $Export | Export-Csv -LiteralPath $CsvPath -NoTypeInformation -Encoding UTF8
    Write-SuccessMsg ('Expiring-certificate listing written: {0}' -f $CsvPath)

    $RetainFilter = '{0}_ExpiringCerts_*.csv' -f $script:ScriptName
    Limit-TimestampedFiles -Directory $script:CertScanReportRoot -Filter $RetainFilter -KeepCount $script:CertScanRetainCount

    return $CsvPath
}

function Get-CertScanWorkerError
{
    param
    (
        [Parameter(Mandatory = $true)]
        [PSCustomObject]$ServerResult
    )

    $LastError = $null
    foreach ($Entry in @($ServerResult.LogEntries))
    {
        $Tag = ([string]$Entry.Tag).Trim()
        if ($Tag -eq 'ERROR' -or $Tag -eq 'WARN')
        {
            $LastError = ([string]$Entry.Message).Trim()
        }
    }

    return $LastError
}

function Get-CertScanServerStatus
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$Results,

        [Parameter(Mandatory = $true)]
        [string]$TargetDate
    )

    $StatusList = [System.Collections.Generic.List[PSCustomObject]]::new()

    foreach ($ServerResult in $Results)
    {
        $Reachable = [string]$ServerResult.Reachable
        $Count     = [int]$ServerResult.MatchCount
        $LogError  = Get-CertScanWorkerError -ServerResult $ServerResult

        if ($Count -gt 0)
        {
            $Status = 'Met criteria'
            $Reason = '{0} certificate(s) expire on {1}.' -f $Count, $TargetDate
        }
        elseif ($Reachable -eq 'Yes')
        {
            if (-not [string]::IsNullOrWhiteSpace($LogError))
            {
                $Status = 'Error'
                $Reason = $LogError
            }
            else
            {
                $Status = 'No match'
                $Reason = 'Reachable; no certificate expires on {0}.' -f $TargetDate
            }
        }
        elseif ($Reachable -eq 'Session failed')
        {
            $Status = 'Error'
            $Reason = if (-not [string]::IsNullOrWhiteSpace($LogError)) { $LogError } else { 'PSSession could not be opened.' }
        }
        elseif ($Reachable -eq 'No')
        {
            $Status = 'Unreachable'
            $Reason = if (-not [string]::IsNullOrWhiteSpace($LogError)) { $LogError } else { 'Not reachable over WinRM.' }
        }
        else
        {
            $Status = 'Unknown'
            $Reason = if (-not [string]::IsNullOrWhiteSpace($LogError)) { $LogError } else { ('Reachable state: {0}' -f $Reachable) }
        }

        $StatusList.Add([PSCustomObject]@{
            Server     = $ServerResult.Server
            Fqdn       = $ServerResult.Fqdn
            Status     = $Status
            MatchCount = $Count
            Reason     = $Reason
        })
    }

    return $StatusList
}

