        }

        $Row = @"
<tr>
  <td>$($Item.Server)</td>
  <td>$($Item.Fqdn)</td>
  <td style="color:$Color;font-weight:bold;">$($Item.Status)</td>
  <td style="text-align:center;">$($Item.MatchCount)</td>
  <td>$($Item.Reason)</td>
</tr>
"@
        $Rows.Add($Row)
    }

    if ($Rows.Count -eq 0)
    {
        $Rows.Add('<tr><td colspan="5" style="text-align:center;color:#57606a;">No servers were scanned.</td></tr>')
    }

    $RowsHtml = $Rows -join [Environment]::NewLine

    $Html = @"
<html>
<head>
<style>
    body  { font-family: Segoe UI, Arial, sans-serif; font-size: 12px; color: #1f2328; }
    h2    { color: #0b3d91; margin-bottom: 2px; }
    .meta { color: #57606a; font-size: 12px; margin-top: 0; }
    table { border-collapse: collapse; width: 100%; margin-top: 12px; }
    th    { background: #0b3d91; color: #ffffff; text-align: left; padding: 6px 8px; font-size: 11px; }
    td    { border: 1px solid #d0d7de; padding: 5px 8px; vertical-align: top; }
    tr:nth-child(even) td { background: #f6f8fa; }
</style>
</head>
<body>
    <h2>$($script:ReportTitle) - Scanned Server Results</h2>
    <p class="meta">Scan expiry date: $TargetDate &nbsp;|&nbsp; Generated: $($script:FriendlyDate) &nbsp;|&nbsp; Domain: $($script:CertScanADServer) &nbsp;|&nbsp; Servers scanned: $($StatusList.Count)</p>
