function Save-CertScanHtmlReport
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Html,

        [Parameter(Mandatory = $true)]
        [string]$Suffix
    )

    if (-not (Test-Path -LiteralPath $script:CertScanReportRoot))
    {
        $null = New-Item -Path $script:CertScanReportRoot -ItemType Directory -Force
    }

    $FileName = '{0}_{1}_{2}.html' -f $script:ScriptName, $Suffix, $script:RunStamp
    $HtmlPath = Join-Path -Path $script:CertScanReportRoot -ChildPath $FileName

    $Utf8 = New-Object System.Text.UTF8Encoding($true)
    [System.IO.File]::WriteAllText($HtmlPath, $Html, $Utf8)
    Write-SuccessMsg ('HTML report written: {0}' -f $HtmlPath)

    $RetainFilter = '{0}_{1}_*.html' -f $script:ScriptName, $Suffix
    Limit-TimestampedFiles -Directory $script:CertScanReportRoot -Filter $RetainFilter -KeepCount $script:CertScanRetainCount

    return $HtmlPath
}

# ============================================================
# REGION: CRL MAINTENANCE
# ============================================================

function Test-CrlMenuPassword
{
    for ($Attempt = 1; $Attempt -le $script:CrlMenuMaxAttempts; $Attempt++)
    {
        $Secure = Read-Host -Prompt 'Enter the CRL maintenance password' -AsSecureString
        $Plain  = ''
        $Bstr   = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($Secure)

        try
        {
            $Plain = [System.Runtime.InteropServices.Marshal]::PtrToStringBSTR($Bstr)
        }
        finally
        {
            [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($Bstr)
        }

        $Match = ($Plain -eq $script:CrlMenuPassword)
        $Plain = $null

        if ($Match)
        {
            Write-SuccessMsg 'CRL maintenance password accepted.'
            return $true
        }

        Write-WarnMsg ('Incorrect password (attempt {0} of {1}).' -f $Attempt, $script:CrlMenuMaxAttempts)
    }

    Write-ErrorMsg 'CRL maintenance password validation failed. Returning to the main menu.'
    return $false
}

function Get-RootCaCredential
{
    $Secure = ConvertTo-SecureString -String $script:RootPassword -AsPlainText -Force
    return (New-Object System.Management.Automation.PSCredential($script:RootUsername, $Secure))
}

function Get-RootCrlScript
{
    $Template = @'
$ErrorActionPreference = 'Stop'

certutil -crl
if ($LASTEXITCODE -ne 0)
{
    throw "certutil -crl failed with exit code $LASTEXITCODE"
}

$CRL = Get-ChildItem -Path '@@CERT_ENROLL@@' -Filter '@@CRL_PATTERN@@' |
       Sort-Object LastWriteTime -Descending |
       Select-Object -First 1

Copy-Item -Path $CRL.FullName -Destination '@@CRL_SHARE@@' -Force
Copy-Item -Path $CRL.FullName -Destination '@@CRL_SUB_CERTENROLL@@' -Force
'@

    $Text = $Template
    $Text = $Text.Replace('@@CERT_ENROLL@@',        $script:CertEnrollPath)
    $Text = $Text.Replace('@@CRL_PATTERN@@',        $script:CRLNamePattern)
    $Text = $Text.Replace('@@CRL_SHARE@@',          $script:CRLSharePath)
    $Text = $Text.Replace('@@CRL_SUB_CERTENROLL@@', $script:CRLSubCertEnrollPath)

    return $Text
}

function Get-PublishCrlScript
{
    $Template = @'
$ErrorActionPreference = 'Stop'

certutil -dspublish -f '@@SUB_CRL@@' '@@ROOT_CA@@'
if ($LASTEXITCODE -ne 0)
{
    throw "certutil -dspublish failed with exit code $LASTEXITCODE"
}

$Dump = certutil -dump '@@SUB_CRL@@'
if ($Dump -notmatch '@@ISSUER@@')
{
    throw 'CRL issuer does not match expected Root CA.'
}
'@

    $Text = $Template
    $Text = $Text.Replace('@@SUB_CRL@@', $script:SubCACRLPath)
    $Text = $Text.Replace('@@ROOT_CA@@', $script:RootCAServer)
    $Text = $Text.Replace('@@ISSUER@@',  $script:RootCaIssuerName)

    return $Text
}

function Connect-PkiVCenter
{
    Write-InfoMsg ('Connecting to vCenter {0}' -f $script:vCenterServer)
    $null = Connect-VIServer -Server $script:vCenterServer
    Write-SuccessMsg 'vCenter connection established.'
}

function Disconnect-PkiVCenter
{
    Write-InfoMsg ('Disconnecting from vCenter {0}' -f $script:vCenterServer)
    Disconnect-VIServer -Confirm:$false
    Write-SuccessMsg 'vCenter connection closed.'
}

function Get-PkiVm
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$Name
    )

    $Vm = Get-VM -Name $Name -ErrorAction SilentlyContinue
    if (-not $Vm)
    {
        throw ('VM "{0}" not found in vCenter.' -f $Name)
    }

    return $Vm
}

function Start-RootCa
{
    param
    (
        [Parameter(Mandatory = $true)]
        [object]$RootVM
    )

    Write-InfoMsg ('Powering on {0}' -f $script:RootCAServer)
    $null = Start-VM -VM $RootVM -Confirm:$false

    Write-InfoMsg ('Waiting up to {0} seconds for VMware Tools on {1}' -f $script:ToolsTimeoutSeconds, $script:RootCAServer)
    Wait-Tools -VM $RootVM -TimeoutSeconds $script:ToolsTimeoutSeconds

    $Refreshed = Get-VM -Name $script:RootCAServer

    if ($Refreshed.ExtensionData.Guest.ToolsStatus -ne 'toolsOk')
    {
        throw ('VMware Tools did not report healthy status on {0}.' -f $script:RootCAServer)
    }

    Write-SuccessMsg ('{0} is powered on and VMware Tools report healthy.' -f $script:RootCAServer)
    return $Refreshed
}

function Stop-RootCa
{
    param
    (
        [Parameter(Mandatory = $true)]
        [object]$RootVM
    )

    Write-InfoMsg ('Powering off {0}' -f $script:RootCAServer)
    $null = Stop-VM -VM $RootVM -Confirm:$false
    Write-SuccessMsg ('{0} powered off.' -f $script:RootCAServer)
}

function Invoke-RootCrlGeneration
{
    param
    (
        [Parameter(Mandatory = $true)]
        [object]$RootVM,

        [Parameter(Mandatory = $true)]
        [System.Management.Automation.PSCredential]$RootCred
    )

    Write-InfoMsg ('Executing Root CRL generation on {0}' -f $script:RootCAServer)

    $ScriptText = Get-RootCrlScript
    $VMScriptSplat = @{
        VM              = $RootVM
        ScriptType      = 'PowerShell'
        ScriptText      = $ScriptText
        GuestCredential = $RootCred
    }

    $null = Invoke-VMScript @VMScriptSplat
    Write-SuccessMsg 'Root CRL generated and copied to the Sub CA share and CertEnroll directory.'
}

function Invoke-RootCrlPublication
{
    param
    (
        [Parameter(Mandatory = $true)]
        [object]$SubVM
    )

    Write-InfoMsg ('Publishing Root CRL to Active Directory and validating issuer on {0}' -f $script:SubCAServer)

    $ScriptText = Get-PublishCrlScript
    $VMScriptSplat = @{
        VM         = $SubVM
        ScriptType = 'PowerShell'
        ScriptText = $ScriptText
    }

    $null = Invoke-VMScript @VMScriptSplat
    Write-SuccessMsg ('Root CRL published to AD and issuer validated against "{0}".' -f $script:RootCaIssuerName)
}

function Show-CrlVerificationMenu
{
    Write-Host ''
    Write-Host '=============== MANUAL VERIFICATION ===============' -ForegroundColor Cyan
    Write-Host ('  1. Open pkiview.msc on {0}' -f $script:SubCAServer)            -ForegroundColor White
    Write-Host ('  2. Confirm "{0}" shows GREEN' -f $script:RootCaIssuerName)     -ForegroundColor White
    Write-Host '  3. Verify Next Update is approximately 6 months + 1 day'        -ForegroundColor White
    Write-Host '===================================================' -ForegroundColor Cyan
    Write-Host ''

    Write-Log -Message 'Displayed manual verification menu for Sub CA pkiview checks.' -Tag 'INFO '
}

function Show-CrlDryRunPlan
{
    Write-DryRunMsg 'The following actions WOULD be performed for the Root CRL update. No changes will be made during this dry run.'
    Write-DryRunMsg ('Step 1  : Build a Root CA guest credential for "{0}" to authenticate Invoke-VMScript on {1}.' -f $script:RootUsername, $script:RootCAServer)
    Write-DryRunMsg ('Step 2  : Connect to vCenter server {0}.' -f $script:vCenterServer)
    Write-DryRunMsg ('Step 3  : Validate that the VMs "{0}" and "{1}" exist in vCenter inventory.' -f $script:RootCAServer, $script:SubCAServer)
    Write-DryRunMsg ('Step 4  : Read the power state of {0}. If it is powered off, power it on, wait up to {1} seconds for VMware Tools, and confirm Tools report "toolsOk".' -f $script:RootCAServer, $script:ToolsTimeoutSeconds)
    Write-DryRunMsg ('Step 5  : On {0}, run "certutil -crl" to generate a fresh Root CRL.' -f $script:RootCAServer)
    Write-DryRunMsg ('Step 5a : Locate the newest CRL matching "{0}" under {1}.' -f $script:CRLNamePattern, $script:CertEnrollPath)
    Write-DryRunMsg ('Step 5b : Copy that CRL to {0}.' -f $script:CRLSharePath)
    Write-DryRunMsg ('Step 5c : Copy that CRL to {0}.' -f $script:CRLSubCertEnrollPath)
    Write-DryRunMsg ('Step 6  : If this tool powered {0} on in Step 4, power it back off afterward.' -f $script:RootCAServer)
    Write-DryRunMsg ('Step 7  : On {0}, publish the CRL to Active Directory: certutil -dspublish -f "{1}" "{2}".' -f $script:SubCAServer, $script:SubCACRLPath, $script:RootCAServer)
    Write-DryRunMsg ('Step 7a : Dump {0} and confirm the issuer contains "{1}".' -f $script:SubCACRLPath, $script:RootCaIssuerName)
    Write-DryRunMsg ('Step 8  : Display the manual verification menu (pkiview.msc checks on {0}).' -f $script:SubCAServer)
    Write-DryRunMsg ('Step 9  : Disconnect from vCenter {0}. This always runs, even on error.' -f $script:vCenterServer)
}

function Invoke-CrlMaintenance
{
    param
    (
        [Parameter(Mandatory = $true)]
        [bool]$DryRun
    )

    if ($DryRun)
    {
        Show-CrlDryRunPlan
        return
    }

    if (-not (Get-Command -Name 'Connect-VIServer' -ErrorAction SilentlyContinue))
    {
        Write-ErrorMsg 'VMware PowerCLI is not available in this session (Connect-VIServer not found). Import VMware.PowerCLI and retry.'
        return
    }

    # Fail-fast within this operation only; scope is local to the function.
    $ErrorActionPreference = 'Stop'

    $RootCred    = Get-RootCaCredential
    $Connected   = $false
    $StartedRoot = $false

    try
    {
        Connect-PkiVCenter
        $Connected = $true

        $RootVM = Get-PkiVm -Name $script:RootCAServer
        $SubVM  = Get-PkiVm -Name $script:SubCAServer
        Write-SuccessMsg 'VM pre-flight validation successful.'

        $RootOriginallyPoweredOn = ($RootVM.PowerState -eq 'PoweredOn')

        if (-not $RootOriginallyPoweredOn)
        {
            $RootVM      = Start-RootCa -RootVM $RootVM
            $StartedRoot = $true
        }
        else
        {
            Write-InfoMsg ('{0} is already powered on; leaving its power state unchanged.' -f $script:RootCAServer)
        }

        Invoke-RootCrlGeneration -RootVM $RootVM -RootCred $RootCred

        if ($StartedRoot)
        {
            Stop-RootCa -RootVM $RootVM
        }
        else
        {
            Write-InfoMsg ('{0} was already running before this run; leaving it powered on.' -f $script:RootCAServer)
        }

        Invoke-RootCrlPublication -SubVM $SubVM

        Show-CrlVerificationMenu

        Write-SuccessMsg 'PKI Root CRL maintenance completed successfully.'
    }
    catch
    {
        Write-ErrorMsg ('Root CRL maintenance failed: {0}' -f $_.Exception.Message)
    }
    finally
    {
        if ($Connected)
        {
            try
            {
                Disconnect-PkiVCenter
            }
            catch
            {
                Write-WarnMsg ('vCenter disconnect reported an issue: {0}' -f $_.Exception.Message)
            }
        }
    }
}

# ============================================================
# REGION: 45-DAY CERTIFICATE EXPIRATION REPORT (MENU OPTION 7)
# ============================================================

function Get-ExpiryReportParentOU
{
    param
    (
        [Parameter(Mandatory = $true)]
        [string]$CanonicalName
    )

    # CanonicalName is "domain/OU/.../Object"; drop the trailing object
    # segment to yield the friendly parent OU path.
    $Index = $CanonicalName.LastIndexOf('/')

    if ($Index -lt 0)
    {
        return $CanonicalName
    }

    return $CanonicalName.Substring(0, $Index)
}

function Get-ExpiryReportServerList
{
    Write-InfoMsg 'Enumerating candidate server computer objects from Active Directory.'

    Import-Module ActiveDirectory -ErrorAction Stop

    # Each excluded subtree is identified by the trailing DN fragment that
    # marks it: ",OU=<name>,<MachinesOUBase>" for the Machines sub-OUs, and
    # ",<fullDN>" for any additional OU paths. A computer is skipped if its
    # DN ends with one of these fragments.
    $ExcludedPaths = [System.Collections.Generic.List[string]]::new()

    foreach ($Ou in $script:ExpiryReportExcludedSubOUs)
    {
        $ExcludedPaths.Add((',OU={0},{1}' -f $Ou, $script:ExpiryReportMachinesOUBase))
    }

    foreach ($OuPath in $script:ExpiryReportExcludedOUPaths)
    {
        $ExcludedPaths.Add((',{0}' -f $OuPath))
    }

    $Computers = Get-ADComputer -Properties CanonicalName -Filter {
        Name -like "*WEB*" -or
        Name -like "*INT*" -or
        Name -like "*APP*" -or
        Name -like "*RPT*" -or
        Name -like "*BCA*" -or
        Name -like "*BCW*" -or
        Name -like "*BIR*" -or
        Name -like "*CEV*" -or
        Name -like "*CLC*" -or
        Name -like "*HSW*" -or
        Name -like "*ICX*" -or
        Name -like "*KRP*" -or
        Name -like "*LNK*" -or
        Name -like "*MYC*" -or
        Name -like "*PRT*" -or
        Name -like "*SCA*" -or
        Name -like "*SCL*" -or
        Name -like "*SDW*" -or
        Name -like "*SIG*" -or
        Name -like "*WBS*" -or
        Name -like "*PLS*" -or
        Name -like "*PXY*" -or
        Name -like "*WDM*" -or
        Name -like "*AIO*"
    }

    $Servers = [System.Collections.Generic.List[PSCustomObject]]::new()

    foreach ($Computer in $Computers)
    {
        $Dn       = $Computer.DistinguishedName
        $Excluded = $false

        foreach ($Path in $ExcludedPaths)
        {
            if ($Dn.EndsWith($Path, [System.StringComparison]::OrdinalIgnoreCase))
            {
                $Excluded = $true
                break
            }
        }

        if (-not $Excluded)
        {
            $Servers.Add([PSCustomObject]@{
                Name = $Computer.Name
                OU   = Get-ExpiryReportParentOU -CanonicalName $Computer.CanonicalName
            })
        }
    }

    Write-SuccessMsg ('Server computer objects discovered: {0}' -f $Servers.Count)

    return $Servers
}

function Get-ExpiryReportTemplateMap
{
    # Build a lookup of certificate template identities from Active Directory.
    # The V2 template extension carries the template OID; the V1 extension
    # carries the template common name. Both are mapped to the template's
    # friendly displayName so the scan can resolve a readable name regardless
    # of which extension a certificate carries. Returns an object with two
    # hashtables: ByOid and ByCn.
    Write-InfoMsg 'Building the certificate template friendly-name map from Active Directory.'

    $ByOid = @{}
    $ByCn  = @{}

    try
    {
        Import-Module ActiveDirectory -ErrorAction Stop

        $ConfigNc    = (Get-ADRootDSE -ErrorAction Stop).configurationNamingContext
        $TemplatesDn = 'CN=Certificate Templates,CN=Public Key Services,CN=Services,{0}' -f $ConfigNc

        $GetParams = @{
            SearchBase  = $TemplatesDn
            LDAPFilter  = '(objectClass=pKICertificateTemplate)'
            Properties  = @('cn', 'displayName', 'msPKI-Cert-Template-OID')
            ErrorAction = 'Stop'
        }

        $Templates = Get-ADObject @GetParams

        foreach ($Template in $Templates)
        {
            $Cn       = [string]$Template.cn
            $Friendly = [string]$Template.displayName
            $Oid      = [string]$Template.'msPKI-Cert-Template-OID'

            $Entry = [PSCustomObject]@{
                CommonName   = $Cn
                FriendlyName = $Friendly
            }

            if ($Oid -and -not $ByOid.ContainsKey($Oid))
            {
                $ByOid[$Oid] = $Entry
            }

            if ($Cn -and -not $ByCn.ContainsKey($Cn))
            {
                $ByCn[$Cn] = $Entry
            }
        }

        Write-SuccessMsg ('Certificate templates mapped: {0}' -f $ByOid.Count)
    }
    catch
    {
        Write-WarnMsg ('Template map build failed: {0}. Template names will fall back to the raw value or "N/A".' -f $_.Exception.Message)
    }

    return [PSCustomObject]@{
        ByOid = $ByOid
        ByCn  = $ByCn
    }
}

function Invoke-ExpiryReportScan
{
    param
    (
        [Parameter(Mandatory = $true)]
        $Servers,

        [Parameter(Mandatory = $true)]
        $TemplateMap
    )

    # Per-server worker. Runs in its own runspace, so it receives every value
    # it needs as arguments (no closure over script scope). The inner remote
    # block runs on the target via Invoke-Command and likewise receives the
    # store path and template-extension OIDs as arguments.
    $Worker = {
        param
        (
            $Server,
            $ServerOU,
            $StorePath,
            $Now,
            $Days,
            $TemplateMap,
            $OidTemplateInfo,
            $OidTemplateNameV1
        )

        # ----- WinRM reachability gate (authoritative) -----
        $WinrmOk    = $true
        $WinrmError = ''

        try
        {
            Test-WSMan -ComputerName $Server -ErrorAction Stop | Out-Null
        }
        catch
        {
            $WinrmOk    = $false
            $WinrmError = $_.Exception.Message
        }

        if (-not $WinrmOk)
        {
            # WinRM is the authoritative gate; we are here because it failed.
            # Run an independent diagnostic battery so the report can flag
            # every category that applies (DNS / ICMP / WinRM).
            $NotInDns  = $false
            $NoPing    = $false
            $WinrmDown = $true

            try
            {
                [void][System.Net.Dns]::GetHostAddresses($Server)
            }
            catch
            {
                $NotInDns = $true
            }

            if (-not $NotInDns)
            {
                $PingOk = Test-Connection -ComputerName $Server -Count 1 -Quiet -ErrorAction SilentlyContinue

                if (-not $PingOk)
                {
                    $NoPing = $true
                }
            }

            return [PSCustomObject]@{
                ComputerName = $Server
                Result       = 'Unreachable'
                NotInDns     = $NotInDns
                NoPing       = $NoPing
                WinRMDown    = $WinrmDown
                OU           = $ServerOU
                Detail       = $WinrmError
            }
        }

        try
        {
            $RemoteScript = {
                param
                (
                    $InnerStorePath,
                    $InfoOid,
                    $NameOid
                )

                Get-ChildItem $InnerStorePath | ForEach-Object {
                    $Cert = $_

                    # ----- Certificate template identity -----
                    # The V2 template-information extension carries the
                    # template OID (not its friendly name); the V1 extension
                    # carries the template common name as text. Capture the
                    # raw OID and/or raw name here and resolve the friendly
                    # name on the calling side, where AD is reachable.
                    $TemplateOid     = ''
                    $TemplateNameRaw = ''

                    foreach ($Ext in $Cert.Extensions)
                    {
                        if ($Ext.Oid.Value -eq $InfoOid)
                        {
                            $Asn       = New-Object System.Security.Cryptography.AsnEncodedData($Ext.Oid, $Ext.RawData)
                            $Formatted = $Asn.Format($false)

                            # When the OID resolves locally it appears in
                            # parentheses after the friendly name; otherwise
                            # the bare OID is the value. Capture it either way.
                            if ($Formatted -match '\(([\d\.]+)\)')
                            {
                                $TemplateOid = $matches[1]
                            }
                            elseif ($Formatted -match '(\d+\.\d+\.\d+[\d\.]+)')
                            {
                                $TemplateOid = $matches[1]
                            }

                            break
                        }
                        elseif ($Ext.Oid.Value -eq $NameOid)
                        {
                            $Asn             = New-Object System.Security.Cryptography.AsnEncodedData($Ext.Oid, $Ext.RawData)
                            $TemplateNameRaw = $Asn.Format($false).Trim()

                            break
                        }
                    }

                    # ----- EKU usage classification -----
                    $Usage = ''
                    foreach ($Eku in $Cert.EnhancedKeyUsageList)
                    {
                        if ($Eku.FriendlyName -eq 'Server Authentication')
                        {
                            $Usage = 'Server'
                        }
                        elseif ($Eku.FriendlyName -eq 'Client Authentication' -and $Usage -ne 'Server')
                        {
                            $Usage = 'Client'
                        }
                    }

                    [PSCustomObject]@{
                        Issuer          = $Cert.Issuer
                        Subject         = $Cert.Subject
                        NotAfter        = $Cert.NotAfter
                        Usage           = $Usage
                        TemplateOid     = $TemplateOid
                        TemplateNameRaw = $TemplateNameRaw
                    }
                }
            }

            $Certs = Invoke-Command -ComputerName $Server -ScriptBlock $RemoteScript -ArgumentList $StorePath, $OidTemplateInfo, $OidTemplateNameV1

            foreach ($Cert in $Certs)
            {
                $Usage         = $Cert.Usage
                $DaysRemaining = ($Cert.NotAfter - $Now).Days

                if ($Usage -and ($Cert.NotAfter -lt $Now -or $DaysRemaining -le $Days))
                {
                    # ----- Resolve the template friendly name -----
                    # Prefer the AD displayName (friendly), then the common
                    # name; fall back to the raw extension value, then 'N/A'.
                    # Lookup keys come from the remote cert: V2 OID first,
                    # then V1 common name.
                    $TemplateDisplay = ''

                    if ($Cert.TemplateOid -and $TemplateMap.ByOid.ContainsKey($Cert.TemplateOid))
                    {
                        $Entry = $TemplateMap.ByOid[$Cert.TemplateOid]

                        if ($Entry.FriendlyName)
                        {
                            $TemplateDisplay = $Entry.FriendlyName
                        }
                        elseif ($Entry.CommonName)
                        {
                            $TemplateDisplay = $Entry.CommonName
                        }
                    }
                    elseif ($Cert.TemplateNameRaw -and $TemplateMap.ByCn.ContainsKey($Cert.TemplateNameRaw))
                    {
                        $Entry = $TemplateMap.ByCn[$Cert.TemplateNameRaw]

                        if ($Entry.FriendlyName)
                        {
                            $TemplateDisplay = $Entry.FriendlyName
                        }
                        elseif ($Entry.CommonName)
                        {
                            $TemplateDisplay = $Entry.CommonName
                        }
                    }

                    if (-not $TemplateDisplay -and $Cert.TemplateNameRaw)
                    {
                        $TemplateDisplay = $Cert.TemplateNameRaw
                    }

                    if (-not $TemplateDisplay)
                    {
                        $TemplateDisplay = 'N/A'
                    }

                    [PSCustomObject]@{
                        ComputerName   = $Server
                        IssuerCN       = ($Cert.Issuer -split ',')[0] -replace '^CN='
                        SubjectCN      = ($Cert.Subject -split ',')[0] -replace '^CN='
                        TemplateName   = $TemplateDisplay
                        ExpirationDate = $Cert.NotAfter
                        DaysRemaining  = $DaysRemaining
                        Usage          = $Usage
                        Status         = $(if ($Cert.NotAfter -lt $Now) { 'Expired' } else { 'ExpiringSoon' })
                        Result         = 'Success'
                    }
                }
            }
        }
        catch
        {
            [PSCustomObject]@{
                ComputerName = $Server
                Result       = 'Failed'
                Reason       = 'Certificate retrieval failed'
                Detail       = $_.Exception.Message
            }
        }
    }

    $Now  = Get-Date
    $Pool = [runspacefactory]::CreateRunspacePool(1, $script:ExpiryReportThrottleLimit)
    $Pool.Open()

    $Jobs = [System.Collections.Generic.List[object]]::new()
    $Bag  = [System.Collections.Concurrent.ConcurrentBag[object]]::new()

    foreach ($Server in $Servers)
    {
        $PS = [powershell]::Create()
        $PS.RunspacePool = $Pool

        [void]$PS.AddScript($Worker.ToString())
        [void]$PS.AddArgument($Server.Name)
        [void]$PS.AddArgument($Server.OU)
        [void]$PS.AddArgument($script:ExpiryReportStorePath)
        [void]$PS.AddArgument($Now)
        [void]$PS.AddArgument($script:ExpiryReportDaysThreshold)
        [void]$PS.AddArgument($TemplateMap)
        [void]$PS.AddArgument($script:OidTemplateInfo)
        [void]$PS.AddArgument($script:OidTemplateNameV1)

        $Jobs.Add([PSCustomObject]@{
            Pipe   = $PS
            Handle = $PS.BeginInvoke()
        })
    }

    $Total     = $Jobs.Count
    $Completed = 0
    Write-Progress -Activity $script:ExpiryReportProgressActivity -Status ('0 of {0} complete' -f $Total) -PercentComplete 0

    while ($Jobs.Count -gt 0)
    {
        for ($Index = $Jobs.Count - 1; $Index -ge 0; $Index--)
        {
            if ($Jobs[$Index].Handle.IsCompleted)
            {
                $Output = $Jobs[$Index].Pipe.EndInvoke($Jobs[$Index].Handle)

                foreach ($Item in @($Output))
                {
                    if ($Item)
                    {
                        $Bag.Add($Item)
                    }
                }

                $Jobs[$Index].Pipe.Dispose()
                $Jobs.RemoveAt($Index)

                $Completed++
                $Percent = [int][math]::Min(100, ($Completed / $Total) * 100)
                Write-Progress -Activity $script:ExpiryReportProgressActivity -Status ('{0} of {1} complete' -f $Completed, $Total) -PercentComplete $Percent
            }
        }

        Start-Sleep -Milliseconds 100
    }

    Write-Progress -Activity $script:ExpiryReportProgressActivity -Completed

    $Pool.Close()
    $Pool.Dispose()

    return $Bag.ToArray()
}

function Get-ExpiryReportEmailSubject
{
    $DateStamp = Get-Date -Format 'MM-dd-yyyy'
    return ('Certerator {0} Day Expiring Certificate Report - {1}' -f $script:ExpiryReportDaysThreshold, $DateStamp)
}

function Build-ExpiryReportBody
{
    param
    (
        [Parameter(Mandatory = $true)]
        [AllowEmptyCollection()]
        [object[]]$Results,

        [Parameter(Mandatory = $true)]
        [AllowEmptyCollection()]
        [object[]]$Report,

        [Parameter(Mandatory = $true)]
        [int]$InputCount,

        [Parameter(Mandatory = $true)]
        [TimeSpan]$Duration
    )

    $ExpectedIssuer = $script:ExpiryReportExpectedIssuer

    # ----- Filter to UH-issued Server certificates expiring soon -----
    $Filtered = $Report | Where-Object {
        $_.Status   -eq 'ExpiringSoon' -and
        $_.IssuerCN -like ('*{0}*' -f $ExpectedIssuer) -and
        $_.Usage    -eq 'Server'
    }

    # ----- Summary data -----
    $Valid  = $Results | Where-Object { $_.ComputerName }
    $Unique = $Valid   | Select-Object -ExpandProperty ComputerName -Unique

    $ServersInList = $InputCount
    $Success = ($Valid | Where-Object { $_.Result -eq 'Success' }).Count
    $Unreach = ($Valid | Where-Object { $_.Result -eq 'Unreachable' }).Count
    $Failed  = ($Valid | Where-Object { $_.Result -eq 'Failed' }).Count

    $ExpSoon = ($Report | Where-Object {
        $_.Status   -eq 'ExpiringSoon' -and
        $_.Usage    -eq 'Server' -and
        $_.IssuerCN -like ('*{0}*' -f $ExpectedIssuer)
    }).Count

    # ----- Unreachable data -----
    $UnreachableList = @($Results |
        Where-Object { $_.Result -eq 'Unreachable' } |
        Group-Object ComputerName |
        ForEach-Object { $_.Group | Select-Object -First 1 } |
        Sort-Object ComputerName)

    $DnsCount   = @($UnreachableList | Where-Object { $_.NotInDns  }).Count
    $PingCount  = @($UnreachableList | Where-Object { $_.NoPing    }).Count
    $WinrmCount = @($UnreachableList | Where-Object { $_.WinRMDown }).Count

    # ----- Table rows -----
    $SortOrder = @(
        @{ Expression = { $_.DaysRemaining }; Descending = $true  }
        @{ Expression = { $_.ComputerName  }; Descending = $false }
    )

    $Rows = foreach ($Row in ($Filtered | Sort-Object $SortOrder))
    {
        if ($Row.DaysRemaining -lt 5)
        {
            $Bg = 'background-color:#cc0000;color:white;font-weight:bold;'
        }
        elseif ($Row.DaysRemaining -lt 10)
        {
            $Bg = 'background-color:#ff4d4d;'
        }
        elseif ($Row.DaysRemaining -le 20)
        {
            $Bg = 'background-color:#ffff66;'
        }
        else
        {
            $Bg = 'background-color:#66ff66;'
        }

        ('<tr style="{0}">' +
            '<td style="white-space:nowrap;"><b>{1}</b></td>' +
            '<td style="white-space:nowrap;">{2}</td>' +
            '<td style="white-space:nowrap;">{3}</td>' +
            '<td style="white-space:nowrap;">{4}</td>' +
            '<td style="white-space:nowrap;">{5}</td>' +
        '</tr>') -f $Bg, $Row.ComputerName, $Row.IssuerCN, $Row.DaysRemaining, $Row.ExpirationDate.ToString('yyyy-MM-dd HH:mm:ss'), $Row.TemplateName
    }

    $RowsJoined = $Rows -join [Environment]::NewLine

    # ----- Execution summary -----
    $SummaryHtml = @"
<br><br>
<h3>Execution Summary</h3>
<table border="1" cellpadding="5" cellspacing="0">
<tr><td>Servers in List</td><td>$ServersInList</td></tr>
<tr><td>Total Servers Processed</td><td>$($Unique.Count)</td></tr>
<tr><td>Successful Scans</td><td style="color:green;">$Success</td></tr>
<tr><td>Unreachable Servers</td><td style="color:red;">$Unreach</td></tr>
<tr><td>Failed Scans</td><td style="color:red;">$Failed</td></tr>
<tr><td>UH Server Certs Expiring Soon (&lt;=$($script:ExpiryReportDaysThreshold) days)</td><td style="color:orange;">$ExpSoon</td></tr>
<tr><td>Total Certificates</td><td>$($Report.Count)</td></tr>
<tr><td>Duration</td><td>$($Duration.ToString('hh\:mm\:ss'))</td></tr>
</table>
"@

    # ----- Unreachable breakdown -----
    if ($UnreachableList)
    {
        $UnreachableHtml = @"
<br><br>
<h3 style="color:#cc0000;">Unreachable Servers ($($UnreachableList.Count))</h3>
<p>These servers could not be scanned. The failure categories are summarized below.</p>
<table border="1" cellpadding="5" cellspacing="0">
<tr><th>Failure Category</th><th>Servers</th></tr>
<tr><td>Not in DNS</td><td style="text-align:center;">$DnsCount</td></tr>
<tr><td>No Ping</td><td style="text-align:center;">$PingCount</td></tr>
<tr><td>WinRM Not Responding</td><td style="text-align:center;">$WinrmCount</td></tr>
</table>
"@
    }
    else
    {
        $UnreachableHtml = @"
<br><br>
<h3 style="color:green;">Unreachable Servers (0)</h3>
<p>All discovered servers were reachable.</p>
"@
    }

    # ----- Inline logo (placed above the report heading) -----
    $LogoBlock = ''
    if ($script:EmailLogoEnabled -and -not [string]::IsNullOrWhiteSpace($script:EmailLogoBase64))
    {
        $LogoBlock = '<img src="cid:{0}" width="{1}" height="{2}" alt="{3}" style="display:block; border:0; border-radius:6px; margin-bottom:12px;" />' -f $script:EmailLogoContentId, $script:EmailLogoWidth, $script:EmailLogoHeight, $script:ReportTitle
    }

    # ----- Final email body -----
    $Body = @"
<html>
<body>

$LogoBlock

<h2>UH Server Certificates Expiring Within $($script:ExpiryReportDaysThreshold) Days</h2>

<table border="1" cellpadding="5" cellspacing="0">
<tr>
<th style="white-space:nowrap;">Server</th>
<th style="white-space:nowrap;">Issuer</th>
<th style="white-space:nowrap;">Days</th>
<th style="white-space:nowrap;">Expiration</th>
<th style="white-space:nowrap;">Template Name</th>
</tr>
$RowsJoined
</table>

$SummaryHtml

$UnreachableHtml

</body>
</html>
"@

    return $Body
}

function Invoke-ExpiryReport
{
    Write-Host ''
    Write-Host "----- $script:ExpiryReportDaysThreshold Day Certificate Expiration Report -----" -ForegroundColor Cyan

    $StartTime = Get-Date

    try
    {
        $Servers = Get-ExpiryReportServerList
    }
    catch
    {
        Write-ErrorMsg ('Active Directory discovery failed: {0}' -f $_.Exception.Message)
        return
    }

    if (-not $Servers -or $Servers.Count -eq 0)
    {
        Write-WarnMsg 'No matching server computer objects were discovered. Returning to the main menu.'
        return
    }

    $TemplateMap = Get-ExpiryReportTemplateMap

    Write-InfoMsg ('Scanning {0} server(s) for certificates expiring within {1} day(s).' -f $Servers.Count, $script:ExpiryReportDaysThreshold)

    $Results = Invoke-ExpiryReportScan -Servers $Servers -TemplateMap $TemplateMap

    # Items that carry a Status property are the matched certificate rows;
    # unreachable / failed records have no Status and are excluded here.
    $Report   = @($Results | Where-Object { $_.Status })
    $Duration = (Get-Date) - $StartTime

    $Valid       = @($Results | Where-Object { $_.ComputerName })
    $SuccessCnt  = @($Valid | Where-Object { $_.Result -eq 'Success' }).Count
    $UnreachCnt  = @($Valid | Where-Object { $_.Result -eq 'Unreachable' }).Count
    $FailedCnt   = @($Valid | Where-Object { $_.Result -eq 'Failed' }).Count
    $ExpiringCnt = @($Report | Where-Object {
        $_.Status   -eq 'ExpiringSoon' -and
        $_.Usage    -eq 'Server' -and
        $_.IssuerCN -like ('*{0}*' -f $script:ExpiryReportExpectedIssuer)
    }).Count

    Write-InfoMsg    ('Servers discovered : {0}' -f $Servers.Count)
    Write-InfoMsg    ('Matched cert rows  : {0}' -f $SuccessCnt)
    Write-InfoMsg    ('Unreachable servers: {0}' -f $UnreachCnt)
    Write-InfoMsg    ('Failed scans       : {0}' -f $FailedCnt)
    Write-SuccessMsg ('UH Server certificates expiring within {0} day(s): {1}' -f $script:ExpiryReportDaysThreshold, $ExpiringCnt)
    Write-InfoMsg    ('Scan duration      : {0}' -f $Duration.ToString('hh\:mm\:ss'))

    $Body = Build-ExpiryReportBody -Results $Results -Report $Report -InputCount $Servers.Count -Duration $Duration

    Send-ReportEmail -HtmlBody $Body -Subject (Get-ExpiryReportEmailSubject) -IncludeLogo
}

# ============================================================
# REGION: MENU FUNCTIONS
# ============================================================


function Show-MainMenu
{
    Write-Host ''
    Write-Host '==================== ' -ForegroundColor Cyan -NoNewline
    Write-Host "JEFF'S CERTERATOR"     -ForegroundColor Yellow -NoNewline
    Write-Host ' ===================' -ForegroundColor Cyan
    Write-Host '  1. Create new certificate(s)'                                           -ForegroundColor White
    Write-Host '  2. Renew a certificate from an existing CSR'                            -ForegroundColor White
    Write-Host '  3. Inspect a PFX (export CER/CRT, show details)'                        -ForegroundColor White
    Write-Host '  4. Modify a certificate and create a new one'                           -ForegroundColor White
    Write-Host '  5. Update Root CRL (password protected)'                                -ForegroundColor White
    Write-Host '  6. Scan domain for certificates expiring on a date'                     -ForegroundColor White
    Write-Host "  7. $script:ExpiryReportDaysThreshold Day Certificate Expiration Report" -ForegroundColor White
    Write-Host '  8. Exit'                                                                -ForegroundColor White
    Write-Host '==========================================================' -ForegroundColor Cyan
    return (Read-Host 'Select an option')
}

function Select-Template
{
    Write-Host ''
    Write-Host '----- Certificate Template -----' -ForegroundColor Cyan
    foreach ($Key in $script:CertTemplates.Keys)
    {
        Write-Host ('  {0}. {1}' -f $Key, $script:CertTemplates[$Key].FriendlyName) -ForegroundColor White
    }
    Write-Host '--------------------------------' -ForegroundColor Cyan
    Write-Host '  (Press ENTER or Q to return to the main menu)' -ForegroundColor DarkGray

    while ($true)
    {
        $Choice = Read-Host 'Select a template'

        if ([string]::IsNullOrWhiteSpace($Choice) -or $Choice.Trim() -match '(?i)^q$')
        {
            Write-InfoMsg 'No template selected. Returning to the main menu.'
            return $null
        }

        if ($script:CertTemplates.Contains($Choice.Trim()))
        {
            $Friendly = $script:CertTemplates[$Choice.Trim()].FriendlyName
            $Submit   = $script:CertTemplates[$Choice.Trim()].CommonName
            Write-InfoMsg ('Template selected: {0} (submitting as: {1})' -f $Friendly, $Submit)
            return $Submit
        }

        Write-WarnMsg 'Invalid template selection. Try again.'
    }
}

function Get-ServerList
{
    Write-Host ''
    Write-Host '----- Server Input -----' -ForegroundColor Cyan
    Write-Host '  1. Enter a single server name' -ForegroundColor White
    Write-Host '  2. Read a list of servers from a file' -ForegroundColor White
    Write-Host '  (Press ENTER or Q to return to the main menu)' -ForegroundColor DarkGray
    Write-Host '------------------------' -ForegroundColor Cyan

    $Mode    = Read-Host 'Select an input method'
    $Servers = [System.Collections.Generic.List[string]]::new()

    if ([string]::IsNullOrWhiteSpace($Mode) -or $Mode.Trim() -match '(?i)^q$')
    {
        Write-InfoMsg 'No input method selected. Returning to the main menu.'
        return $Servers
    }

    switch ($Mode.Trim())
    {
        '1'
        {
            $Name = Read-Host 'Enter the server short name (or FQDN) (ENTER or Q to cancel)'
            if ([string]::IsNullOrWhiteSpace($Name) -or $Name.Trim() -match '(?i)^q$')
            {
                Write-InfoMsg 'No server name entered. Returning to the main menu.'
                return $Servers
            }

            $Short = Get-ShortNameFromValue -Value $Name
            if ($Short -ne '')
            {
                $Servers.Add($Short)
            }
        }

        '2'
        {
            $Path = Read-Host 'Enter the full path to the server list file (one name per line) (ENTER or Q to cancel)'
            if ([string]::IsNullOrWhiteSpace($Path) -or $Path.Trim() -match '(?i)^q$')
            {
                Write-InfoMsg 'No file path entered. Returning to the main menu.'
                return $Servers
            }

            if (Test-Path -LiteralPath $Path)
            {
                $Lines = Get-Content -LiteralPath $Path |
                    ForEach-Object { $_.Trim() } |
                    Where-Object { $_ -ne '' -and $_ -notmatch '^\s*#' }

                foreach ($Line in $Lines)
                {
                    $Short = Get-ShortNameFromValue -Value $Line
                    if ($Short -ne '' -and -not $Servers.Contains($Short))
                    {
                        $Servers.Add($Short)
                    }
                }

                Write-InfoMsg ('Loaded {0} server(s) from {1}' -f $Servers.Count, $Path)
            }
            else
            {
                Write-ErrorMsg ('Server list file not found: {0}' -f $Path)
            }
        }

        default
        {
            Write-WarnMsg 'Invalid input method selection.'
        }
    }

    return $Servers
}

function Invoke-CreateCertificates
{
    $Template = Select-Template
    if ([string]::IsNullOrWhiteSpace($Template))
    {
        return
    }

    $Servers  = Get-ServerList

    if ($Servers.Count -eq 0)
    {
        Write-WarnMsg 'No servers were provided. Returning to the main menu.'
        return
    }

    Write-Host ''
    Write-Host 'Extra Subject Alternative Names are added in addition to the' -ForegroundColor DarkGray
    Write-Host 'short name, FQDN, and <short>.uhhospitals.org defaults.'       -ForegroundColor DarkGray
    $ExtraDns = Read-DelimitedInput -Prompt 'Extra DNS SAN entries (comma-separated, blank for none)'
    $ExtraIp  = Read-DelimitedInput -Prompt 'Extra IP SAN entries (comma-separated, blank for none)'

    $WorkItems = [System.Collections.Generic.List[PSCustomObject]]::new()

    foreach ($Server in $Servers)
    {
        $San = Build-SanList -ShortName $Server -ExtraDns $ExtraDns -ExtraIp $ExtraIp

        $WorkItems.Add([PSCustomObject]@{
            ShortName   = $Server
            CommonName  = $San.CommonName
            DnsNames    = $San.DnsNames
            IpAddresses = $San.IpAddresses
            Template    = $Template
            RunMode     = 'Create'
        })
    }

    Complete-Run -WorkItems $WorkItems -RunMode 'Create'
}

function Invoke-RenewFromCsr
{
    $CsrPath = Read-Host 'Enter the full path to the existing CSR file (ENTER to cancel)'

    if ([string]::IsNullOrWhiteSpace($CsrPath))
    {
        Write-InfoMsg 'No CSR file entered. Returning to the main menu.'
        return
    }

    if (-not (Test-Path -LiteralPath $CsrPath))
    {
        Write-ErrorMsg ('CSR file not found: {0}' -f $CsrPath)
        return
    }

    $Parsed = Read-ExistingCsr -CsrPath $CsrPath
    if (-not $Parsed)
    {
        Write-ErrorMsg 'Unable to build a renewal from the supplied CSR.'
        return
    }

    $Template = Select-Template
    if ([string]::IsNullOrWhiteSpace($Template))
    {
        return
    }

    Write-Host ''
    Write-Host 'You may add extra SANs to the renewal in addition to those' -ForegroundColor DarkGray
    Write-Host 'carried over from the original CSR.'                        -ForegroundColor DarkGray
    $ExtraDns = Read-DelimitedInput -Prompt 'Additional DNS SAN entries (comma-separated, blank for none)'
    $ExtraIp  = Read-DelimitedInput -Prompt 'Additional IP SAN entries (comma-separated, blank for none)'

    $ShortName = Get-ShortNameFromValue -Value $Parsed.CommonName

    $DnsNames = [System.Collections.Generic.List[string]]::new()
    if (-not $DnsNames.Contains($Parsed.CommonName))
    {
        $DnsNames.Add($Parsed.CommonName)
    }
    foreach ($Name in @($Parsed.DnsNames) + $ExtraDns)
    {
        if ([string]::IsNullOrWhiteSpace($Name))
        {
            continue
        }

        $Clean = $Name.Trim()
        if ($Clean -ne '' -and -not $DnsNames.Contains($Clean))
        {
            $DnsNames.Add($Clean)
        }
    }

    $IpAddresses = [System.Collections.Generic.List[string]]::new()
    foreach ($Ip in @($Parsed.IpAddresses) + $ExtraIp)
    {
        if ([string]::IsNullOrWhiteSpace($Ip))
        {
            continue
        }

        $Clean = $Ip.Trim()
        if ($Clean -ne '' -and -not $IpAddresses.Contains($Clean))
        {
            $IpAddresses.Add($Clean)
        }
    }

    $WorkItems = [System.Collections.Generic.List[PSCustomObject]]::new()
    $WorkItems.Add([PSCustomObject]@{
        ShortName   = $ShortName
        CommonName  = $Parsed.CommonName
        DnsNames    = $DnsNames
        IpAddresses = $IpAddresses
        Template    = $Template
        RunMode     = 'Renew'
    })

    Complete-Run -WorkItems $WorkItems -RunMode 'Renew'
}

function Invoke-InspectPfx
{
    $PfxPath = Read-Host 'Enter the full path to the PFX file (ENTER to cancel)'

    if ([string]::IsNullOrWhiteSpace($PfxPath))
    {
        Write-InfoMsg 'No PFX file entered. Returning to the main menu.'
        return
    }

    if (-not (Test-Path -LiteralPath $PfxPath))
    {
        Write-ErrorMsg ('PFX file not found: {0}' -f $PfxPath)
        return
    }

    $Password = Read-PfxFilePassword
    $Cert     = Import-PfxCertificateObject -PfxPath $PfxPath -Password $Password

    if (-not $Cert)
    {
        return
    }

    $BaseName = [System.IO.Path]::GetFileNameWithoutExtension($PfxPath)

    try
    {
        $null = Export-CerAndCrt -Cert $Cert -BaseName $BaseName
    }
    catch
    {
        Write-WarnMsg ('CER/CRT export failed: {0}' -f $_.Exception.Message)
    }

    $null = Show-CertificateDetails -Cert $Cert
}

function Invoke-ModifyAndRecreate
{
    $PfxPath = Read-Host 'Enter the full path to the source PFX file (ENTER to cancel)'

    if ([string]::IsNullOrWhiteSpace($PfxPath))
    {
        Write-InfoMsg 'No PFX file entered. Returning to the main menu.'
        return
    }

    if (-not (Test-Path -LiteralPath $PfxPath))
    {
        Write-ErrorMsg ('PFX file not found: {0}' -f $PfxPath)
        return
    }

    $Password = Read-PfxFilePassword
    $Cert     = Import-PfxCertificateObject -PfxPath $PfxPath -Password $Password

    if (-not $Cert)
    {
        return
    }

    $Details = Show-CertificateDetails -Cert $Cert

    Write-Host ''
    Write-Host '----- Modify Certificate Data -----' -ForegroundColor Cyan
    Write-Host 'Press Enter to keep the current value shown in brackets.' -ForegroundColor DarkGray

    $NewCommonName = Read-WithDefault -Prompt 'Common Name (CN)' -Default $Details.CommonName
    if ([string]::IsNullOrWhiteSpace($NewCommonName))
    {
        Write-ErrorMsg 'A Common Name is required to build a new certificate.'
        return
    }

    $CountryDefault = if ([string]::IsNullOrWhiteSpace($Details.Country))      { $script:Country }      else { $Details.Country }
    $StateDefault   = if ([string]::IsNullOrWhiteSpace($Details.State))        { $script:State }        else { $Details.State }
    $LocalDefault   = if ([string]::IsNullOrWhiteSpace($Details.Locality))     { $script:Locality }     else { $Details.Locality }
    $OrgDefault     = if ([string]::IsNullOrWhiteSpace($Details.Organization)) { $script:Organization } else { $Details.Organization }
    $OuDefault      = if ([string]::IsNullOrWhiteSpace($Details.OrgUnit))      { $script:OrgUnit }      else { $Details.OrgUnit }

    $NewCountry      = Read-WithDefault -Prompt 'Country (C)'          -Default $CountryDefault
    $NewState        = Read-WithDefault -Prompt 'State / Province (S)' -Default $StateDefault
    $NewLocality     = Read-WithDefault -Prompt 'Locality (L)'         -Default $LocalDefault
    $NewOrganization = Read-WithDefault -Prompt 'Organization (O)'     -Default $OrgDefault
    $NewOrgUnit      = Read-WithDefault -Prompt 'Org. Unit (OU)'       -Default $OuDefault

    $DnsDefault = ($Details.DnsNames -join ', ')
    $IpDefault  = ($Details.IpAddresses -join ', ')

    Write-Host ''
    Write-Host 'Enter the full SAN lists below (comma-separated). The current' -ForegroundColor DarkGray
    Write-Host 'values are pre-filled as the default; edit them as needed.'    -ForegroundColor DarkGray

    $DnsRaw = Read-WithDefault -Prompt 'DNS SAN entries' -Default $DnsDefault
    $IpRaw  = Read-WithDefault -Prompt 'IP SAN entries'  -Default $IpDefault

    $DnsNames = [System.Collections.Generic.List[string]]::new()
    if (-not $DnsNames.Contains($NewCommonName))
    {
        $DnsNames.Add($NewCommonName)
    }
    foreach ($Item in ($DnsRaw -split '[,;]'))
    {
        $Clean = $Item.Trim()
        if ($Clean -ne '' -and -not $DnsNames.Contains($Clean))
        {
            $DnsNames.Add($Clean)
        }
    }

    $IpAddresses = [System.Collections.Generic.List[string]]::new()
    foreach ($Item in ($IpRaw -split '[,;]'))
    {
        $Clean = $Item.Trim()
        if ($Clean -ne '' -and -not $IpAddresses.Contains($Clean))
        {
            $IpAddresses.Add($Clean)
        }
    }

    $Template  = Select-Template
    $ShortName = Get-ShortNameFromValue -Value $NewCommonName

    $WorkItems = [System.Collections.Generic.List[PSCustomObject]]::new()
    $WorkItems.Add([PSCustomObject]@{
        ShortName   = $ShortName
        CommonName  = $NewCommonName
        DnsNames    = $DnsNames
        IpAddresses = $IpAddresses
        Template    = $Template
        RunMode     = 'Recreate'
    })

    # Temporarily override the script-level Subject locale fields so the
    # existing pipeline emits the modified Distinguished Name, then restore
    # the originals once the run completes.
    $SavedCountry      = $script:Country
    $SavedState        = $script:State
    $SavedLocality     = $script:Locality
    $SavedOrganization = $script:Organization
    $SavedOrgUnit      = $script:OrgUnit
    $SavedDeploy       = $script:DeployToRemote
    $SavedBindIis      = $script:BindIis
    $SavedVerify       = $script:VerifyDeployment

    try
    {
        $script:Country      = $NewCountry
        $script:State        = $NewState
        $script:Locality     = $NewLocality
        $script:Organization = $NewOrganization
        $script:OrgUnit      = $NewOrgUnit

        Write-InfoMsg ('Re-issuing certificate for CN: {0}' -f $NewCommonName)

        $InstallRemotely = Read-RemoteInstallChoice
        if ($InstallRemotely)
        {
            Write-InfoMsg 'Remote install selected. The new certificate will be deployed and bound on the target server(s) over WinRM.'
        }
        else
        {
            $script:DeployToRemote   = $false
            $script:BindIis          = $false
            $script:VerifyDeployment = $false
            Write-InfoMsg ('Local-only mode selected. The new certificate artifacts will be left in {0} and no remote installation will be attempted.' -f (Join-Path -Path $script:OutputRoot -ChildPath $ShortName))
        }

        Complete-Run -WorkItems $WorkItems -RunMode 'Recreate'
    }
    finally
    {
        $script:Country          = $SavedCountry
        $script:State            = $SavedState
        $script:Locality         = $SavedLocality
        $script:Organization     = $SavedOrganization
        $script:OrgUnit          = $SavedOrgUnit
        $script:DeployToRemote   = $SavedDeploy
        $script:BindIis          = $SavedBindIis
        $script:VerifyDeployment = $SavedVerify
    }
}

function Select-CertsToRenew
{
    param
    (
        [Parameter(Mandatory = $true)]
        [System.Collections.Generic.List[PSCustomObject]]$MatchList
    )

    $Chosen = [System.Collections.Generic.List[PSCustomObject]]::new()

    Write-Host ''
    Write-Host '----- Expiring Certificates -----' -ForegroundColor Cyan
    for ($i = 0; $i -lt $MatchList.Count; $i++)
    {
        $Item   = $MatchList[$i]
        $Expiry = if ($Item.NotAfter -is [datetime]) { $Item.NotAfter.ToString('yyyy-MM-dd') } else { [string]$Item.NotAfter }
        Write-Host ('  {0}. {1}  (CN: {2}, expires {3})' -f ($i + 1), $Item.Fqdn, $Item.CommonName, $Expiry) -ForegroundColor White
    }
    Write-Host '---------------------------------' -ForegroundColor Cyan

    Write-Host ''
    Write-Host '  A. Renew ALL listed certificates'        -ForegroundColor White
    Write-Host '  S. Renew SELECTED certificates'          -ForegroundColor White
    Write-Host '  N. Renew NONE (return to the main menu)' -ForegroundColor White

    $Mode = Read-Host 'Choose renewal scope (A/S/N) [N]'

    if ([string]::IsNullOrWhiteSpace($Mode))
    {
        $Mode = 'N'
    }

    switch ($Mode.Trim().ToUpperInvariant())
    {
        'A'
        {
            foreach ($Item in $MatchList)
            {
                $Chosen.Add($Item)
            }
        }

        'S'
        {
            $Raw    = Read-Host 'Enter the numbers to renew (comma/space separated; ranges allowed, e.g. 1,3,5 or 14-28)'
            $Tokens = $Raw -split '[,;\s]+' |
                ForEach-Object { $_.Trim() } |
                Where-Object { $_ -ne '' }

            $Indices = [System.Collections.Generic.List[int]]::new()

            foreach ($Token in $Tokens)
            {
                if ($Token -match '^\d+\s*-\s*\d+$')
                {
                    $Bounds = $Token -split '-'
                    $Start  = [int]$Bounds[0].Trim()
                    $End    = [int]$Bounds[1].Trim()

                    if ($Start -gt $End)
                    {
                        $Swap  = $Start
                        $Start = $End
                        $End   = $Swap
                    }

                    for ($Range = $Start; $Range -le $End; $Range++)
                    {
                        if ($Range -ge 1 -and $Range -le $MatchList.Count)
                        {
                            if (-not $Indices.Contains($Range))
                            {
                                $Indices.Add($Range)
                            }
                        }
                        else
                        {
                            Write-WarnMsg ('Selection {0} (from range {1}) is out of range and was ignored.' -f $Range, $Token)
                        }
                    }
                }
                else
                {
                    $Index = 0
                    if ([int]::TryParse($Token, [ref]$Index))
                    {
                        if ($Index -ge 1 -and $Index -le $MatchList.Count)
                        {
                            if (-not $Indices.Contains($Index))
                            {
                                $Indices.Add($Index)
                            }
                        }
                        else
                        {
                            Write-WarnMsg ('Selection {0} is out of range and was ignored.' -f $Token)
                        }
                    }
                    else
                    {
                        Write-WarnMsg ('Selection "{0}" is not a number or range and was ignored.' -f $Token)
                    }
                }
            }

            foreach ($Index in $Indices)
            {
                $Candidate = $MatchList[$Index - 1]
                if (-not $Chosen.Contains($Candidate))
                {
                    $Chosen.Add($Candidate)
                }
            }
        }

        default
        {
            Write-InfoMsg 'No certificates selected for renewal.'
        }
    }

    return $Chosen
}

function Invoke-ScanExpiringCertificates
{
    Write-Host ''
    $TargetDate = Read-Host 'Target expiry date to scan for (defaults to 10/31/2026 🎃)'

    if ([string]::IsNullOrWhiteSpace($TargetDate))
    {
        $TargetDate = $script:CertScanTargetDate
    }

    $ParsedDate = [datetime]::MinValue
    if (-not [datetime]::TryParse($TargetDate, [ref]$ParsedDate))
    {
        Write-ErrorMsg ('"{0}" is not a valid date. Use the yyyy-MM-dd format.' -f $TargetDate)
        return
    }

    $script:CertScanResolvedDate = $ParsedDate.ToString('yyyy-MM-dd')
    Write-InfoMsg ('Scanning the {0} domain for certificates expiring on {1}.' -f $script:CertScanADServer, $script:CertScanResolvedDate)

    if ($script:DryRun)
    {
        Write-DryRunMsg ('Would query {0} for server computer objects matching the configured filter.' -f $script:CertScanADServer)
        Write-DryRunMsg ('Would open a WinRM session to each reachable server and inspect {0} for certificates expiring on {1}.' -f $script:CertScanStorePath, $script:CertScanResolvedDate)
        Write-DryRunMsg 'Would write two HTML reports (scanned-server results and the expiring-certificate listing) plus a CSV listing, email a summary with both HTML reports attached, then offer to renew the matches.'
        return
    }

    # A live scan opens remote sessions; acquire a credential up front.
    if (-not (Request-RemoteCredential))
    {
        return
    }

    $Stopwatch = [System.Diagnostics.Stopwatch]::StartNew()

    $Servers = Get-DomainServerList
    if ($Servers.Count -eq 0)
    {
        $Stopwatch.Stop()
        Write-WarnMsg 'No server computer objects were returned. Returning to the main menu.'
        return
    }

    $ScanMusic = Start-ScanMusic

    try
    {
        $ScanResults = Start-CertScan -WorkItems $Servers
    }
    finally
    {
        Stop-ScanMusic -Music $ScanMusic
    }

    $Stopwatch.Stop()
    Show-ScanLogs -Results $ScanResults

    $ElapsedText = Format-ScanElapsed -Elapsed $Stopwatch.Elapsed

    $MatchList = [System.Collections.Generic.List[PSCustomObject]]::new()
    foreach ($ServerResult in $ScanResults)
    {
        foreach ($Hit in $ServerResult.Matches)
        {
            $MatchList.Add($Hit)
        }
    }

    $ServersMatched = @($ScanResults | Where-Object { [int]$_.MatchCount -gt 0 }).Count
    $TotalObjects   = [int]$script:CertScanLastTotalObjects
    $Excluded       = [int]$script:CertScanLastExcluded
    $Scanned        = $Servers.Count

    # Console summary of the completed scan.
    Write-Host ''
    Write-InfoMsg ('Scan expiration date            : {0}' -f $script:CertScanResolvedDate)
    Write-InfoMsg ('Computer objects discovered     : {0}' -f $TotalObjects)
    Write-InfoMsg ('Excluded by pattern             : {0}' -f $Excluded)
    Write-InfoMsg ('Servers scanned                 : {0}' -f $Scanned)
    Write-InfoMsg ('Servers meeting scan criteria   : {0}' -f $ServersMatched)
    Write-InfoMsg ('Certificates meeting criteria   : {0}' -f $MatchList.Count)
    Write-InfoMsg ('Scan duration                   : {0}' -f $ElapsedText)

    # Report 1: every scanned server with pass/fail status and reason.
    $StatusList   = Get-CertScanServerStatus -Results $ScanResults -TargetDate $script:CertScanResolvedDate
    $ServerHtml   = Build-CertScanServerReport -StatusList $StatusList -TargetDate $script:CertScanResolvedDate
    $ServerReport = Save-CertScanHtmlReport -Html $ServerHtml -Suffix 'ScannedServers'

    # Report 2: full listing of servers and certificates that met the scan criteria.
    $MatchHtml   = Build-CertScanHtmlReport -MatchList $MatchList -TargetDate $script:CertScanResolvedDate
    $MatchReport = Save-CertScanHtmlReport -Html $MatchHtml -Suffix 'ExpiringCerts'

    # Machine-readable CSV listing retained alongside the HTML reports.
    $null = Export-CertScanListing -MatchList $MatchList

    $SummaryBody = Build-CertScanSummaryBody -TotalObjects $TotalObjects -Excluded $Excluded -Scanned $Scanned -ServersMatched $ServersMatched -CertificatesMatched $MatchList.Count -TargetDate $script:CertScanResolvedDate -Elapsed $ElapsedText
    $Subject     = Get-CertScanEmailSubject -TargetDate $script:CertScanResolvedDate -MatchCount $MatchList.Count

    Send-ReportEmail -HtmlBody $SummaryBody -Subject $Subject -Attachments @($ServerReport, $MatchReport) -IncludeLogo

    if ($MatchList.Count -eq 0)
    {
        Write-InfoMsg ('No certificates expiring on {0} were found across {1} server(s).' -f $script:CertScanResolvedDate, $Scanned)
        return
    }

    Write-SuccessMsg ('Found {0} certificate(s) expiring on {1} across {2} server(s).' -f $MatchList.Count, $script:CertScanResolvedDate, $Scanned)

    $ToRenew = Select-CertsToRenew -MatchList $MatchList
    if ($ToRenew.Count -eq 0)
    {
        Write-InfoMsg 'No certificates were selected for renewal. Returning to the main menu.'
        return
    }

    $Template = Select-Template
    if ([string]::IsNullOrWhiteSpace($Template))
    {
        return
    }

    $WorkItems = [System.Collections.Generic.List[PSCustomObject]]::new()
    foreach ($Item in $ToRenew)
    {
        $CommonName = if (-not [string]::IsNullOrWhiteSpace($Item.CommonName)) { $Item.CommonName } else { $Item.Fqdn }
        $ShortName  = Get-ShortNameFromValue -Value $Item.Server

        $DnsNames = [System.Collections.Generic.List[string]]::new()
        if (-not $DnsNames.Contains($CommonName))
        {
            $DnsNames.Add($CommonName)
        }
        foreach ($Name in @($Item.DnsSans))
        {
            $Clean = ([string]$Name).Trim()
            if ($Clean -ne '' -and -not $DnsNames.Contains($Clean))
            {
                $DnsNames.Add($Clean)
            }
        }

        $IpAddresses = [System.Collections.Generic.List[string]]::new()
        foreach ($Ip in @($Item.IpSans))
        {
            $Clean = ([string]$Ip).Trim()
            if ($Clean -ne '' -and -not $IpAddresses.Contains($Clean))
            {
                $IpAddresses.Add($Clean)
            }
        }

        $WorkItems.Add([PSCustomObject]@{
            ShortName   = $ShortName
            CommonName  = $CommonName
            DnsNames    = $DnsNames
            IpAddresses = $IpAddresses
            Template    = $Template
            RunMode     = 'Renew'
        })
    }

    Write-InfoMsg ('Renewing {0} certificate(s) through the issuing pipeline.' -f $WorkItems.Count)
    Complete-Run -WorkItems $WorkItems -RunMode 'Renew'
}

function Invoke-UpdateCrl
{
    if (-not (Test-CrlMenuPassword))
    {
        return
    }

    Write-InfoMsg 'Starting Root CRL maintenance in DRYRUN mode. The steps below will only be described; nothing will be changed yet.'
    Invoke-CrlMaintenance -DryRun $true

    Write-Host ''
    $Answer = Read-Host 'The dry run above lists every action. Perform the Root CRL update for real now? (Y/N) [N]'

    if ([string]::IsNullOrWhiteSpace($Answer) -or $Answer.Trim() -notmatch '(?i)^y')
    {
        Write-InfoMsg 'Root CRL update cancelled by operator. No changes were made.'
        return
    }

    Write-InfoMsg 'Operator confirmed. Executing the Root CRL update for real.'
    Invoke-CrlMaintenance -DryRun $false
}

# ============================================================
# REGION: MAIN
# ============================================================

Initialize-Logging

if (-not (Test-Prerequisites))
{
    Write-ErrorMsg 'Prerequisite checks failed. Resolve the issues above and re-run.'
    exit 1
}

try
{
    $Running = $true
    while ($Running)
    {
        $Selection = Show-MainMenu

        switch ($Selection)
        {
            '1'
            {
                Invoke-CreateCertificates
            }

            '2'
            {
                Invoke-RenewFromCsr
            }

            '3'
            {
                Invoke-InspectPfx
            }

            '4'
            {
                Invoke-ModifyAndRecreate
            }

            '5'
            {
                Invoke-UpdateCrl
            }

            '6'
            {
                Invoke-ScanExpiringCertificates
            }

            '7'
            {
                Invoke-ExpiryReport
            }

            '8'
            {
                $Running = $false
            }

            default
            {
                Write-WarnMsg 'Invalid selection. Choose 1, 2, 3, 4, 5, 6, 7, or 8.'
            }
        }
    }

    exit 0
}
catch
{
    Write-ErrorMsg ('Unhandled error: {0}' -f $_.Exception.Message)
    exit 1
}
